UPDATE words SET example_en_2 = 'Hello! It''s so nice to see you here.', example_ko_2 = '안녕하세요! 여기서 만나니 정말 반가워요.', example_en_3 = 'She said hello to everyone in the office.', example_ko_3 = '그녀는 사무실의 모든 사람에게 안녕이라고 인사했어요.', example_en_4 = 'Don''t forget to say hello when you arrive.', example_ko_4 = '도착하면 인사하는 것 잊지 마세요.', example_en_5 = 'He always says hello with a big smile.', example_ko_5 = '그는 항상 환한 미소로 인사해요.' WHERE id = 'w_greeting_A1_01';
UPDATE words SET example_en_2 = 'She waved and said hi from across the street.', example_ko_2 = '그녀는 길 건너에서 손을 흔들며 하이라고 했어요.', example_en_3 = 'Just say hi — it''s a friendly gesture.', example_ko_3 = '그냥 하이라고 해요. 친근한 행동이에요.', example_en_4 = 'He texted hi to start the conversation.', example_ko_4 = '그는 대화를 시작하려고 하이라고 문자를 보냈어요.', example_en_5 = 'Say hi to your family for me, please.', example_ko_5 = '가족들에게 제 안부 전해 주세요.' WHERE id = 'w_greeting_A1_02';
UPDATE words SET example_en_2 = 'She said goodbye and waved at the door.', example_ko_2 = '그녀는 문에서 작별 인사를 하며 손을 흔들었어요.', example_en_3 = 'Don''t forget to say goodbye before you leave.', example_ko_3 = '떠나기 전에 작별 인사 잊지 마세요.', example_en_4 = 'Saying goodbye was harder than we thought.', example_ko_4 = '작별 인사를 하는 것이 생각보다 더 어려웠어요.', example_en_5 = 'He said goodbye with a warm hug.', example_ko_5 = '그는 따뜻한 포옹으로 작별 인사를 했어요.' WHERE id = 'w_greeting_A1_03';
UPDATE words SET example_en_2 = 'She smiled and said bye at the end of the party.', example_ko_2 = '그녀는 파티가 끝나고 미소를 지으며 바이라고 했어요.', example_en_3 = 'He waved bye and got into the taxi.', example_ko_3 = '그는 바이라고 손을 흔들며 택시에 탔어요.', example_en_4 = 'Just say bye quickly so we don''t miss the train.', example_ko_4 = '기차를 놓치지 않도록 빨리 바이라고 해요.', example_en_5 = 'She texted bye when the meeting ended.', example_ko_5 = '회의가 끝났을 때 그녀는 바이라고 문자를 보냈어요.' WHERE id = 'w_greeting_A1_04';
UPDATE words SET example_en_2 = 'Could you pass the menu, please?', example_ko_2 = '메뉴판 좀 건네주실 수 있나요, 부탁드려요.', example_en_3 = 'Please speak slowly so I can understand.', example_ko_3 = '이해할 수 있도록 천천히 말씀해 주세요.', example_en_4 = 'Please wait a moment — I''ll be right back.', example_ko_4 = '잠깐만 기다려 주세요. 바로 돌아올게요.', example_en_5 = 'Sit down, please, and make yourself comfortable.', example_ko_5 = '앉아 주세요, 편하게 쉬세요.' WHERE id = 'w_greeting_A1_05';
UPDATE words SET example_en_2 = 'Thank you for helping me with my bags.', example_ko_2 = '가방을 들어 주셔서 감사해요.', example_en_3 = 'I always say thank you when someone holds the door.', example_ko_3 = '누군가가 문을 잡아줄 때 항상 감사하다고 해요.', example_en_4 = 'Thank you for coming all this way to see me.', example_ko_4 = '이렇게 멀리까지 만나러 와 주셔서 감사해요.', example_en_5 = 'She said thank you with a warm smile.', example_ko_5 = '그녀는 따뜻한 미소로 감사하다고 했어요.' WHERE id = 'w_greeting_A1_06';
UPDATE words SET example_en_2 = 'He said sorry for being late to the meeting.', example_ko_2 = '그는 회의에 늦어서 죄송하다고 했어요.', example_en_3 = 'I''m sorry if I said something rude.', example_ko_3 = '제가 무례한 말을 했다면 죄송해요.', example_en_4 = 'She smiled and said sorry with a gentle bow.', example_ko_4 = '그녀는 미소를 지으며 가볍게 고개를 숙여 죄송하다고 했어요.', example_en_5 = 'Always say sorry when you make a mistake.', example_ko_5 = '실수를 하면 항상 죄송하다고 말하세요.' WHERE id = 'w_greeting_A1_07';
UPDATE words SET example_en_2 = 'She said yes to the dinner invitation.', example_ko_2 = '그녀는 저녁 초대에 네라고 했어요.', example_en_3 = 'Did you say yes to joining the team?', example_ko_3 = '팀에 합류하는 것에 네라고 했나요?', example_en_4 = 'He smiled and nodded yes at her question.', example_ko_4 = '그는 그녀의 질문에 미소를 지으며 네라고 고개를 끄덕였어요.', example_en_5 = 'Just say yes if you agree with the plan.', example_ko_5 = '계획에 동의하면 네라고 하세요.' WHERE id = 'w_greeting_A1_08';
UPDATE words SET example_en_2 = 'She politely said no to the offer.', example_ko_2 = '그녀는 제안에 정중하게 아니요라고 했어요.', example_en_3 = 'It''s okay to say no when you are uncomfortable.', example_ko_3 = '불편할 때는 아니요라고 해도 괜찮아요.', example_en_4 = 'He shook his head and said no quietly.', example_ko_4 = '그는 조용히 고개를 흔들며 아니요라고 했어요.', example_en_5 = 'Don''t be afraid to say no when necessary.', example_ko_5 = '필요할 때는 아니요라고 말하는 것을 두려워하지 마세요.' WHERE id = 'w_greeting_A1_09';
UPDATE words SET example_en_2 = 'What is your name? I''d love to know.', example_ko_2 = '성함이 어떻게 되세요? 알고 싶어요.', example_en_3 = 'Her name is hard to pronounce at first.', example_ko_3 = '그녀의 이름은 처음에 발음하기 어려워요.', example_en_4 = 'Please write your name on the form.', example_ko_4 = '양식에 이름을 적어 주세요.', example_en_5 = 'I forgot his name — how embarrassing!', example_ko_5 = '그의 이름을 잊어버렸어요. 정말 당황스러워요!' WHERE id = 'w_greeting_A1_10';
UPDATE words SET example_en_2 = 'It was so nice to finally meet you in person.', example_ko_2 = '드디어 직접 만나게 되어 정말 반가웠어요.', example_en_3 = 'She has such a nice way of greeting people.', example_ko_3 = '그녀는 사람들에게 인사하는 방식이 참 좋아요.', example_en_4 = 'What a nice surprise to see you here!', example_ko_4 = '여기서 만나다니 정말 반가운 놀라움이에요!', example_en_5 = 'He always says something nice when he first meets someone.', example_ko_5 = '그는 처음 만날 때 항상 좋은 말을 해요.' WHERE id = 'w_greeting_A1_11';
UPDATE words SET example_en_2 = 'I am happy to meet new people at this event.', example_ko_2 = '이 행사에서 새로운 사람들을 만나게 되어 기뻐요.', example_en_3 = 'Let''s meet for coffee and catch up!', example_ko_3 = '커피 마시며 근황을 나눠요!', example_en_4 = 'It was great to meet everyone at the workshop.', example_ko_4 = '워크샵에서 모두를 만나게 되어 정말 좋았어요.', example_en_5 = 'Where did you first meet your best friend?', example_ko_5 = '가장 친한 친구를 처음 어디서 만났어요?' WHERE id = 'w_greeting_A1_12';
UPDATE words SET example_en_2 = 'She says good morning to everyone she passes.', example_ko_2 = '그녀는 지나치는 모든 사람에게 좋은 아침이에요라고 인사해요.', example_en_3 = 'Good morning! Did you sleep well last night?', example_ko_3 = '좋은 아침이에요! 어젯밤에 잘 주무셨어요?', example_en_4 = 'He texted good morning to start the day.', example_ko_4 = '그는 하루를 시작하며 좋은 아침이에요라고 문자를 보냈어요.', example_en_5 = 'A simple good morning can brighten someone''s day.', example_ko_5 = '간단한 좋은 아침이에요 한마디가 누군가의 하루를 밝게 해줄 수 있어요.' WHERE id = 'w_greeting_A1_13';
UPDATE words SET example_en_2 = 'She greeted the guests with a warm good evening.', example_ko_2 = '그녀는 손님들에게 따뜻한 좋은 저녁이에요로 인사했어요.', example_en_3 = 'Good evening — please come in and sit down.', example_ko_3 = '좋은 저녁이에요. 들어오셔서 앉으세요.', example_en_4 = 'He said good evening as he arrived at the party.', example_ko_4 = '그는 파티에 도착하며 좋은 저녁이에요라고 했어요.', example_en_5 = 'Good evening! Can I get you something to drink?', example_ko_5 = '좋은 저녁이에요! 마실 것을 가져다드릴까요?' WHERE id = 'w_greeting_A1_14';
UPDATE words SET example_en_2 = 'Good night — sweet dreams!', example_ko_2 = '안녕히 주무세요. 좋은 꿈 꾸세요!', example_en_3 = 'She kissed the children and said good night.', example_ko_3 = '그녀는 아이들에게 뽀뽀하고 안녕히 주무세요라고 했어요.', example_en_4 = 'Good night! I''ll see you in the morning.', example_ko_4 = '안녕히 주무세요! 아침에 봬요.', example_en_5 = 'He sent a good night message before going to sleep.', example_ko_5 = '그는 자기 전에 안녕히 주무세요 메시지를 보냈어요.' WHERE id = 'w_greeting_A1_15';
UPDATE words SET example_en_2 = 'Welcome — we are so glad you could come!', example_ko_2 = '환영해요. 와 주셔서 정말 기뻐요!', example_en_3 = 'She felt so welcome at the new office.', example_ko_3 = '그녀는 새 사무실에서 정말 환영받는 느낌이었어요.', example_en_4 = 'Welcome to Korea — I hope you enjoy your stay.', example_ko_4 = '한국에 오신 것을 환영해요. 즐거운 시간 보내세요.', example_en_5 = 'He hung a welcome banner at the entrance.', example_ko_5 = '그는 입구에 환영 현수막을 걸었어요.' WHERE id = 'w_greeting_A1_16';
UPDATE words SET example_en_2 = 'I''m fine, thank you! How about you?', example_ko_2 = '잘 지내요, 감사해요! 당신은요?', example_en_3 = 'She said she was fine even though she was tired.', example_ko_3 = '피곤했지만 그녀는 잘 지낸다고 했어요.', example_en_4 = 'Everything is fine — no need to worry.', example_ko_4 = '다 괜찮아요. 걱정하지 않아도 돼요.', example_en_5 = 'Are you fine? You look a little pale.', example_ko_5 = '괜찮아요? 안색이 좀 안 좋아 보여요.' WHERE id = 'w_greeting_A1_17';
UPDATE words SET example_en_2 = '"How was your day?" he asked with a smile.', example_ko_2 = '"오늘 하루 어땠어요?" 그가 미소를 지으며 물었어요.', example_en_3 = 'How do you say hello in Korean?', example_ko_3 = '한국어로 안녕이라고 어떻게 말해요?', example_en_4 = 'She showed me how to greet people properly.', example_ko_4 = '그녀는 사람들에게 제대로 인사하는 방법을 알려줬어요.', example_en_5 = 'I didn''t know how to start the conversation.', example_ko_5 = '어떻게 대화를 시작해야 할지 몰랐어요.' WHERE id = 'w_greeting_A1_18';
UPDATE words SET example_en_2 = 'I am so happy to see you again after so long.', example_ko_2 = '오랜만에 다시 만나게 되어 정말 기뻐요.', example_en_3 = 'You look great — have you been working out?', example_ko_3 = '정말 좋아 보여요. 운동하고 있어요?', example_en_4 = 'Are you new here? I haven''t seen you before.', example_ko_4 = '여기 처음이에요? 전에 못 봤어요.', example_en_5 = 'Can I sit next to you?', example_ko_5 = '옆에 앉아도 될까요?' WHERE id = 'w_greeting_A1_19';
UPDATE words SET example_en_2 = 'Allow me to introduce my colleague to you.', example_ko_2 = '제 동료를 소개해 드릴게요.', example_en_3 = 'My name is Jisu — please call me by my first name.', example_ko_3 = '제 이름은 지수예요. 이름으로 불러 주세요.', example_en_4 = 'I lost my badge — do you know where it is?', example_ko_4 = '제 배지를 잃어버렸어요. 어디 있는지 아세요?', example_en_5 = 'My friend told me a lot about you.', example_ko_5 = '제 친구가 당신에 대해 많이 이야기해줬어요.' WHERE id = 'w_greeting_A1_20';
UPDATE words SET example_en_2 = 'She introduced me to her friend at the party.', example_ko_2 = '그녀는 파티에서 친구를 소개해 줬어요.', example_en_3 = 'My best friend always greets me with a hug.', example_ko_3 = '가장 친한 친구는 항상 포옹으로 인사해요.', example_en_4 = 'He made a new friend on the first day of work.', example_ko_4 = '그는 출근 첫날 새 친구를 사귀었어요.', example_en_5 = 'Having a friendly colleague makes work more enjoyable.', example_ko_5 = '친근한 동료가 있으면 일이 더 즐거워요.' WHERE id = 'w_greeting_A1_21';
UPDATE words SET example_en_2 = 'I''ll see you tomorrow at the meeting.', example_ko_2 = '내일 회의에서 봬요.', example_en_3 = 'See you soon — take care on the way home.', example_ko_3 = '곧 봬요. 집에 조심히 가세요.', example_en_4 = 'I look forward to seeing you next week.', example_ko_4 = '다음 주에 뵐 것을 기대하고 있어요.', example_en_5 = 'It was so good to see you after all this time.', example_ko_5 = '이렇게 오랜만에 만나게 되어 정말 좋았어요.' WHERE id = 'w_greeting_A1_22';
UPDATE words SET example_en_2 = 'Let''s meet again soon — I had a great time.', example_ko_2 = '곧 또 만나요. 정말 즐거웠어요.', example_en_3 = 'She smiled and said she hoped to see him again.', example_ko_3 = '그녀는 미소를 지으며 다시 만나길 바란다고 했어요.', example_en_4 = 'If you visit again, let me know!', example_ko_4 = '다시 방문하시면 알려 주세요!', example_en_5 = 'We met again at a conference last month.', example_ko_5 = '지난달 컨퍼런스에서 다시 만났어요.' WHERE id = 'w_greeting_A1_23';
UPDATE words SET example_en_2 = 'He is an old friend from university.', example_ko_2 = '그는 대학교 때 오래된 친구예요.', example_en_3 = 'She and I have an old friendship that goes back years.', example_ko_3 = '그녀와 저는 수년이 된 오래된 우정이 있어요.', example_en_4 = 'Old habits die hard — he always bows when he greets.', example_ko_4 = '오래된 습관은 잘 안 바뀌어요. 그는 항상 인사할 때 고개를 숙여요.', example_en_5 = 'I ran into an old classmate at the grocery store.', example_ko_5 = '식료품점에서 오래된 반 친구를 우연히 만났어요.' WHERE id = 'w_greeting_A1_24';
UPDATE words SET example_en_2 = 'Let me introduce our new team member to everyone.', example_ko_2 = '새 팀원을 모두에게 소개할게요.', example_en_3 = 'It''s always exciting to meet new people.', example_ko_3 = '새로운 사람들을 만나는 것은 항상 설레요.', example_en_4 = 'She made a great first impression on her new colleagues.', example_ko_4 = '그녀는 새 동료들에게 좋은 첫인상을 남겼어요.', example_en_5 = 'He felt nervous on his first day at the new job.', example_ko_5 = '그는 새 직장 첫날에 긴장했어요.' WHERE id = 'w_greeting_A1_25';
UPDATE words SET example_en_2 = 'I am delighted to be here with everyone today.', example_ko_2 = '오늘 모두와 함께하게 되어 기뻐요.', example_en_3 = 'I want to introduce myself to the group.', example_ko_3 = '그룹에 자기소개를 하고 싶어요.', example_en_4 = 'I think we have met before — was it at the conference?', example_ko_4 = '전에 만난 적 있는 것 같아요. 컨퍼런스에서였나요?', example_en_5 = 'I am sorry for not recognising you at first!', example_ko_5 = '처음에 못 알아봐서 죄송해요!' WHERE id = 'w_greeting_A1_26';
UPDATE words SET example_en_2 = 'I am so pleased to finally meet you.', example_ko_2 = '드디어 만나게 되어 정말 기뻐요.', example_en_3 = 'I am glad you could join us today.', example_ko_3 = '오늘 함께해 주셔서 기뻐요.', example_en_4 = 'I am Jiwon — I am new to this department.', example_ko_4 = '저는 지원이에요. 이 부서에 새로 왔어요.', example_en_5 = 'I am honoured to be introduced to you.', example_ko_5 = '소개받게 되어 영광이에요.' WHERE id = 'w_greeting_A1_27';
UPDATE words SET example_en_2 = 'You are very kind to say that — thank you!', example_ko_2 = '그렇게 말씀해 주시다니 정말 친절하시네요. 감사해요!', example_en_3 = 'You are the first person I have spoken to today.', example_ko_3 = '오늘 처음으로 이야기를 나눈 분이에요.', example_en_4 = 'I heard you are an expert in this field.', example_ko_4 = '이 분야 전문가이시라고 들었어요.', example_en_5 = 'You are exactly as your friend described!', example_ko_5 = '친구가 설명해 준 것과 정확히 같으시네요!' WHERE id = 'w_greeting_A1_28';
UPDATE words SET example_en_2 = 'I am happy to meet you at last.', example_ko_2 = '드디어 만나게 되어 기뻐요.', example_en_3 = 'She is always happy when she sees old friends.', example_ko_3 = '그녀는 오래된 친구를 만날 때마다 항상 기뻐요.', example_en_4 = 'He looked happy when she walked in.', example_ko_4 = '그녀가 들어왔을 때 그는 기뻐 보였어요.', example_en_5 = 'We were all happy to see each other again.', example_ko_5 = '우리 모두 다시 만나게 되어 기뻤어요.' WHERE id = 'w_greeting_A1_29';
UPDATE words SET example_en_2 = 'I am glad you made it to the event.', example_ko_2 = '행사에 참석해 주셔서 기뻐요.', example_en_3 = 'She said she was glad to finally put a face to the name.', example_ko_3 = '드디어 얼굴을 보게 되어 기쁘다고 그녀가 말했어요.', example_en_4 = 'I am so glad we ran into each other.', example_ko_4 = '우연히 만나게 되어 정말 기뻐요.', example_en_5 = 'He was glad everyone introduced themselves.', example_ko_5 = '모두가 자기소개를 해서 그는 기뻤어요.' WHERE id = 'w_greeting_A1_30';
UPDATE words SET example_en_2 = 'Thanks for being so welcoming on my first day.', example_ko_2 = '첫날에 이렇게 환영해 주셔서 고마워요.', example_en_3 = 'She said thanks and bowed politely.', example_ko_3 = '그녀는 고마워요라고 하며 정중하게 고개를 숙였어요.', example_en_4 = 'Thanks for introducing me to your friends.', example_ko_4 = '친구들에게 소개해 줘서 고마워요.', example_en_5 = 'He gave a quick thanks and headed out.', example_ko_5 = '그는 빠르게 고맙다고 하고 나갔어요.' WHERE id = 'w_greeting_A1_31';
UPDATE words SET example_en_2 = '"Sure, I''d be happy to join you," she replied.', example_ko_2 = '"물론이죠, 기꺼이 함께할게요," 그녀가 대답했어요.', example_en_3 = 'Sure, let me introduce myself first.', example_ko_3 = '물론이죠, 먼저 자기소개를 할게요.', example_en_4 = '"Sure, I know a great place for coffee," he said.', example_ko_4 = '"그럼요, 좋은 커피숍 알아요," 그가 말했어요.', example_en_5 = 'She said sure and shook his hand warmly.', example_ko_5 = '그녀는 그럼요라고 하며 따뜻하게 악수를 했어요.' WHERE id = 'w_greeting_A1_32';
UPDATE words SET example_en_2 = '"Okay, I''ll try to remember your name this time!" she laughed.', example_ko_2 = '"알겠어요, 이번엔 이름 기억할게요!" 그녀가 웃으며 말했어요.', example_en_3 = 'He said okay and smiled back.', example_ko_3 = '그는 알겠어요라고 하며 미소로 답했어요.', example_en_4 = '"Okay, nice to meet you!" he said with a handshake.', example_ko_4 = '"알겠어요, 반가워요!" 그가 악수를 하며 말했어요.', example_en_5 = 'She nodded and said okay when introduced.', example_ko_5 = '소개받을 때 그녀는 고개를 끄덕이며 알겠어요라고 했어요.' WHERE id = 'w_greeting_A1_33';
UPDATE words SET example_en_2 = 'It was great to finally meet you in person.', example_ko_2 = '드디어 직접 만나게 되어 정말 좋았어요.', example_en_3 = 'She had a great first day at the new job.', example_ko_3 = '그녀는 새 직장 첫날이 정말 좋았어요.', example_en_4 = 'What a great way to start a conversation!', example_ko_4 = '대화를 시작하는 정말 좋은 방법이네요!', example_en_5 = 'He thought it was great to see old friends again.', example_ko_5 = '그는 오래된 친구들을 다시 만나게 된 것이 정말 좋았어요.' WHERE id = 'w_greeting_A1_34';
UPDATE words SET example_en_2 = '"Hi there!" she called out as she entered the room.', example_ko_2 = '"안녕하세요!" 그녀가 방에 들어서며 불렀어요.', example_en_3 = 'He greeted the new intern with a cheerful hi there.', example_ko_3 = '그는 새 인턴에게 명랑하게 안녕하세요라고 인사했어요.', example_en_4 = 'Hi there — do you need any help finding a seat?', example_ko_4 = '안녕하세요. 자리 찾는 데 도움이 필요하세요?', example_en_5 = 'She waved and said hi there across the crowded lobby.', example_ko_5 = '그녀는 붐비는 로비 너머로 손을 흔들며 안녕하세요라고 했어요.' WHERE id = 'w_greeting_A1_35';

-- ══════════════════════════════════════
-- A2 (35단어)
-- ══════════════════════════════════════
UPDATE words SET example_en_2 = 'She introduced herself clearly at the start of the meeting.', example_ko_2 = '그녀는 회의 시작에 명확하게 자기소개를 했어요.', example_en_3 = 'Let me introduce myself — I just joined this team.', example_ko_3 = '제 소개를 할게요. 이 팀에 막 합류했어요.', example_en_4 = 'He introduced himself to the new neighbors.', example_ko_4 = '그는 새 이웃들에게 자기소개를 했어요.', example_en_5 = 'Would you like to introduce yourself to the group?', example_ko_5 = '그룹에 자기소개를 해보시겠어요?' WHERE id = 'w_greeting_A2_01';
UPDATE words SET example_en_2 = 'She always greets customers with a friendly hello.', example_ko_2 = '그녀는 항상 고객들에게 친근하게 안녕이라고 인사해요.', example_en_3 = 'He went over to greet the guest at the door.', example_ko_3 = '그는 문에서 손님에게 인사하러 다가갔어요.', example_en_4 = 'It is polite to greet people when you enter a room.', example_ko_4 = '방에 들어갈 때 인사하는 것이 예의 바른 행동이에요.', example_en_5 = 'The host greeted us warmly at the entrance.', example_ko_5 = '호스트가 입구에서 우리를 따뜻하게 맞이했어요.' WHERE id = 'w_greeting_A2_02';
UPDATE words SET example_en_2 = 'The farewell speech made everyone a little emotional.', example_ko_2 = '작별 연설이 모두를 조금 감동적으로 만들었어요.', example_en_3 = 'She wrote a heartfelt farewell card for her colleague.', example_ko_3 = '그녀는 동료를 위해 진심 어린 작별 카드를 썼어요.', example_en_4 = 'They gathered to say farewell before she moved abroad.', example_ko_4 = '그녀가 해외로 떠나기 전에 모두 작별 인사를 하려고 모였어요.', example_en_5 = 'The farewell dinner was warm and full of memories.', example_ko_5 = '작별 만찬은 따뜻하고 추억으로 가득했어요.' WHERE id = 'w_greeting_A2_03';
UPDATE words SET example_en_2 = 'A firm handshake makes a strong first impression.', example_ko_2 = '힘차게 악수하면 강한 첫인상을 남겨요.', example_en_3 = 'She extended her hand for a handshake when they met.', example_ko_3 = '만났을 때 그녀는 악수를 위해 손을 내밀었어요.', example_en_4 = 'In some cultures, a handshake replaces a bow.', example_ko_4 = '일부 문화에서는 악수가 절을 대신해요.', example_en_5 = 'He gave a confident handshake and smiled.', example_ko_5 = '그는 자신 있게 악수를 하며 미소 지었어요.' WHERE id = 'w_greeting_A2_04';
UPDATE words SET example_en_2 = 'It is polite to make eye contact when greeting someone.', example_ko_2 = '인사할 때 눈을 맞추는 것이 예의 바른 행동이에요.', example_en_3 = 'She was always polite and greeted everyone by name.', example_ko_3 = '그녀는 항상 예의 바르게 이름을 불러 인사했어요.', example_en_4 = 'It is polite to wait for someone to finish speaking.', example_ko_4 = '상대방이 말을 마칠 때까지 기다리는 것이 예의예요.', example_en_5 = 'He taught his children to be polite to everyone.', example_ko_5 = '그는 자녀들에게 모든 사람에게 예의 바르게 행동하도록 가르쳤어요.' WHERE id = 'w_greeting_A2_05';
UPDATE words SET example_en_2 = 'He gave a friendly nod when they passed in the hallway.', example_ko_2 = '복도에서 지나칠 때 그는 친근하게 고개를 끄덕였어요.', example_en_3 = 'She has a friendly personality that makes everyone feel at ease.', example_ko_3 = '그녀는 모든 사람을 편안하게 만드는 친근한 성격이에요.', example_en_4 = 'He is always friendly to newcomers.', example_ko_4 = '그는 항상 신입에게 친근하게 대해요.', example_en_5 = 'A friendly smile goes a long way in a first meeting.', example_ko_5 = '처음 만남에서 친근한 미소는 큰 역할을 해요.' WHERE id = 'w_greeting_A2_06';
UPDATE words SET example_en_2 = 'They had a casual conversation while waiting.', example_ko_2 = '기다리는 동안 격식 없는 대화를 나눴어요.', example_en_3 = 'Her casual tone made the meeting feel relaxed.', example_ko_3 = '그녀의 격식 없는 말투가 회의를 편안하게 만들었어요.', example_en_4 = 'A casual wave is fine when you know someone well.', example_ko_4 = '잘 아는 사람에게는 가볍게 손을 흔드는 것으로 충분해요.', example_en_5 = 'He prefers casual greetings over formal ones.', example_ko_5 = '그는 격식 있는 인사보다 격식 없는 인사를 좋아해요.' WHERE id = 'w_greeting_A2_07';
UPDATE words SET example_en_2 = 'The event required formal attire and formal greetings.', example_ko_2 = '그 행사는 격식 있는 복장과 인사를 필요로 했어요.', example_en_3 = 'She used a more formal tone when speaking to senior staff.', example_ko_3 = '그녀는 선임 직원과 대화할 때 더 격식 있는 어조를 사용했어요.', example_en_4 = 'In formal situations, use titles like "Mr." or "Dr."', example_ko_4 = '격식 있는 자리에서는 미스터나 박사 같은 호칭을 사용하세요.', example_en_5 = 'A formal introduction sets the right tone.', example_ko_5 = '격식 있는 소개는 적절한 분위기를 만들어요.' WHERE id = 'w_greeting_A2_08';
UPDATE words SET example_en_2 = 'She waved at her neighbor from the balcony.', example_ko_2 = '그녀는 발코니에서 이웃에게 손을 흔들었어요.', example_en_3 = 'He waved hello as he drove past the house.', example_ko_3 = '그는 집 앞을 지나치며 손을 흔들어 인사했어요.', example_en_4 = 'It is friendly to wave when you recognize someone.', example_ko_4 = '아는 사람을 알아봤을 때 손을 흔드는 것은 친근한 행동이에요.', example_en_5 = 'She waved goodbye from the airport gate.', example_ko_5 = '그녀는 공항 게이트에서 손을 흔들어 작별 인사를 했어요.' WHERE id = 'w_greeting_A2_09';
UPDATE words SET example_en_2 = 'We chatted over coffee before the presentation.', example_ko_2 = '발표 전에 커피를 마시며 이야기를 나눴어요.', example_en_3 = 'She loves to chat with new people at events.', example_ko_3 = '그녀는 행사에서 새로운 사람들과 이야기 나누는 것을 좋아해요.', example_en_4 = 'He chatted with a stranger while waiting in line.', example_ko_4 = '그는 줄 서서 기다리는 동안 낯선 사람과 이야기를 나눴어요.', example_en_5 = 'A quick chat can turn a stranger into a friend.', example_ko_5 = '짧은 대화 한 번이 낯선 사람을 친구로 만들 수 있어요.' WHERE id = 'w_greeting_A2_10';
UPDATE words SET example_en_2 = 'Their first meeting was over coffee last year.', example_ko_2 = '그들의 첫 만남은 지난해 커피를 마시면서였어요.', example_en_3 = 'The meeting started with introductions from everyone.', example_ko_3 = '회의는 모두의 자기소개로 시작됐어요.', example_en_4 = 'She remembered every detail of their first meeting.', example_ko_4 = '그녀는 첫 만남의 모든 세부 사항을 기억했어요.', example_en_5 = 'After the meeting, everyone exchanged contact information.', example_ko_5 = '회의 후 모두 연락처를 교환했어요.' WHERE id = 'w_greeting_A2_11';
UPDATE words SET example_en_2 = 'He asked everyone to introduce yourself in two minutes.', example_ko_2 = '그는 모두에게 2분 안에 자기소개를 해달라고 했어요.', example_en_3 = 'She felt nervous when asked to introduce yourself.', example_ko_3 = '자기소개를 하라고 했을 때 그녀는 긴장했어요.', example_en_4 = 'Please take a moment to introduce yourself to the class.', example_ko_4 = '잠깐 반에 자기소개를 해 주세요.', example_en_5 = 'Introducing yourself with a smile makes it easier.', example_ko_5 = '미소를 지으며 자기소개를 하면 더 편해요.' WHERE id = 'w_greeting_A2_12';
UPDATE words SET example_en_2 = 'It has been a long time — how is your family?', example_ko_2 = '오랜만이에요. 가족은 잘 지내고 있어요?', example_en_3 = 'We haven''t spoken in such a long time!', example_ko_3 = '이렇게 오랫동안 연락이 없었네요!', example_en_4 = 'It felt like a long time even though it was only a year.', example_ko_4 = '1년밖에 안 됐는데도 오랜 것처럼 느껴졌어요.', example_en_5 = 'After such a long time apart, the reunion was emotional.', example_ko_5 = '이렇게 오래 떨어져 있다가 재회하니 감동적이었어요.' WHERE id = 'w_greeting_A2_13';
UPDATE words SET example_en_2 = 'He was pleased to be introduced to the new director.', example_ko_2 = '새 이사님께 소개받게 되어 기뻤어요.', example_en_3 = 'She looked pleased when everyone clapped.', example_ko_3 = '모두가 박수를 쳤을 때 그녀는 기뻐 보였어요.', example_en_4 = 'We are pleased to have you on the team.', example_ko_4 = '팀에 함께하게 되어 기뻐요.', example_en_5 = 'He was pleased to learn they had so much in common.', example_ko_5 = '공통점이 이렇게 많다는 것을 알게 되어 기뻤어요.' WHERE id = 'w_greeting_A2_14';
UPDATE words SET example_en_2 = 'They shook hands and introduced themselves.', example_ko_2 = '그들은 악수를 하며 자기소개를 했어요.', example_en_3 = 'It is customary to shake hands when meeting someone new.', example_ko_3 = '새로운 사람을 만날 때 악수하는 것이 관례예요.', example_en_4 = 'She offered her hand to shake as she introduced herself.', example_ko_4 = '그녀는 자기소개를 하며 악수를 위해 손을 내밀었어요.', example_en_5 = 'He shook hands with each guest as they arrived.', example_ko_5 = '그는 손님들이 도착할 때마다 악수를 했어요.' WHERE id = 'w_greeting_A2_15';
UPDATE words SET example_en_2 = '"See you at the conference next month!" he said.', example_ko_2 = '"다음 달 컨퍼런스에서 봬요!" 그가 말했어요.', example_en_3 = 'She smiled and said see you soon.', example_ko_3 = '그녀는 미소를 지으며 곧 봬요라고 했어요.', example_en_4 = '"See you tomorrow — have a good evening!"', example_ko_4 = '"내일 봬요. 좋은 저녁 보내세요!"', example_en_5 = 'He texted see you and closed his phone.', example_ko_5 = '그는 나중에 봬요라고 문자를 보내고 전화를 닫았어요.' WHERE id = 'w_greeting_A2_16';
UPDATE words SET example_en_2 = '"Take care on your way home," she said warmly.', example_ko_2 = '"집에 조심히 가세요," 그녀가 따뜻하게 말했어요.', example_en_3 = 'He ended every conversation with take care.', example_ko_3 = '그는 모든 대화를 잘 지내요로 마무리했어요.', example_en_4 = '"Take care! We''ll catch up again soon."', example_ko_4 = '"잘 지내요! 곧 다시 근황 나눠요."', example_en_5 = 'She waved and said take care as he left.', example_ko_5 = '그가 떠날 때 그녀는 손을 흔들며 잘 지내요라고 했어요.' WHERE id = 'w_greeting_A2_17';
UPDATE words SET example_en_2 = 'Where do you come from originally?', example_ko_2 = '원래 어디 출신이에요?', example_en_3 = 'I come from a small town in the south.', example_ko_3 = '저는 남쪽의 작은 마을 출신이에요.', example_en_4 = 'She mentioned that she comes from Japan during introductions.', example_ko_4 = '그녀는 자기소개에서 일본 출신이라고 말했어요.', example_en_5 = 'People often ask where I come from when we meet.', example_ko_5 = '만날 때 사람들은 종종 어디 출신인지 물어봐요.' WHERE id = 'w_greeting_A2_18';
UPDATE words SET example_en_2 = 'I work as a teacher at a local school.', example_ko_2 = '저는 지역 학교에서 교사로 일해요.', example_en_3 = 'She works as an engineer — very impressive!', example_ko_3 = '그녀는 엔지니어로 일해요. 정말 인상적이에요!', example_en_4 = 'What do you work as? I work as a nurse.', example_ko_4 = '무슨 일을 하세요? 저는 간호사로 일해요.', example_en_5 = 'He mentioned he works as a translator during the introduction.', example_ko_5 = '그는 자기소개에서 번역가로 일한다고 말했어요.' WHERE id = 'w_greeting_A2_19';
UPDATE words SET example_en_2 = 'I live in Seoul — where do you live?', example_ko_2 = '저는 서울에 살아요. 어디 사세요?', example_en_3 = 'She lives in a quiet neighborhood outside the city.', example_ko_3 = '그녀는 도시 외곽의 조용한 동네에 살아요.', example_en_4 = 'They live in the same apartment building — what a coincidence!', example_ko_4 = '같은 아파트에 살다니 정말 우연이네요!', example_en_5 = 'He mentioned that he lives near the office during their chat.', example_ko_5 = '그는 이야기를 나누면서 사무실 근처에 산다고 했어요.' WHERE id = 'w_greeting_A2_20';
UPDATE words SET example_en_2 = 'It was a pleasure to finally meet you in person.', example_ko_2 = '드디어 직접 만나게 되어 영광이에요.', example_en_3 = 'The pleasure is mine — thank you for coming.', example_ko_3 = '저도 마찬가지예요. 와 주셔서 감사해요.', example_en_4 = 'She said it was a pleasure to work with such a kind team.', example_ko_4 = '이렇게 친절한 팀과 함께 일하게 되어 기쁘다고 그녀가 말했어요.', example_en_5 = 'Meeting you has been a real pleasure.', example_ko_5 = '만나게 되어 정말 기뻤어요.' WHERE id = 'w_greeting_A2_21';
UPDATE words SET example_en_2 = 'It''s nice to meet you too!', example_ko_2 = '저도 만나서 반가워요!', example_en_3 = 'The pleasure is mine too — thanks for the introduction.', example_ko_3 = '저도 마찬가지예요. 소개해 주셔서 감사해요.', example_en_4 = 'She said she too was glad to see them again.', example_ko_4 = '그녀도 다시 만나게 되어 기쁘다고 했어요.', example_en_5 = '"I had a great time too — let''s do this again!"', example_ko_5 = '"저도 정말 즐거웠어요. 또 만나요!"' WHERE id = 'w_greeting_A2_22';
UPDATE words SET example_en_2 = 'She was happy to see her old friend again.', example_ko_2 = '그녀는 오래된 친구를 다시 만나게 되어 기뻤어요.', example_en_3 = 'It''s great to chat with you again after so long.', example_ko_3 = '이렇게 오랜만에 다시 이야기를 나누게 되어 정말 좋아요.', example_en_4 = 'They promised to stay in touch and meet again soon.', example_ko_4 = '그들은 연락을 유지하고 곧 다시 만나기로 약속했어요.', example_en_5 = 'He ran into her again at the same café.', example_ko_5 = '그는 같은 카페에서 그녀를 다시 우연히 만났어요.' WHERE id = 'w_greeting_A2_23';
UPDATE words SET example_en_2 = 'Is there a good café around here?', example_ko_2 = '이 근처에 좋은 카페가 있어요?', example_en_3 = 'She asked if he was new around this part of town.', example_ko_3 = '그녀는 그가 이 동네 근처에 새로 왔는지 물었어요.', example_en_4 = 'There are some great lunch spots around the office.', example_ko_4 = '사무실 근처에 좋은 점심 식당이 몇 군데 있어요.', example_en_5 = 'She looked around to see if she recognized anyone.', example_ko_5 = '그녀는 아는 사람이 있는지 주위를 둘러봤어요.' WHERE id = 'w_greeting_A2_24';
UPDATE words SET example_en_2 = 'That was kind of you to offer your help.', example_ko_2 = '도움을 제안해 주시다니 정말 친절하시네요.', example_en_3 = 'She has such a kind way of speaking to people.', example_ko_3 = '그녀는 사람들에게 말하는 방식이 참 친절해요.', example_en_4 = 'He was very kind and introduced me to everyone.', example_ko_4 = '그는 정말 친절하게 모두에게 저를 소개해 줬어요.', example_en_5 = 'It''s kind of you to say such nice things.', example_ko_5 = '그렇게 좋은 말씀을 해주시다니 정말 친절하시네요.' WHERE id = 'w_greeting_A2_25';
UPDATE words SET example_en_2 = 'I run into her every morning in the office kitchen.', example_ko_2 = '매일 아침 사무실 주방에서 그녀를 마주쳐요.', example_en_3 = 'He introduced himself to his officemates on the first day.', example_ko_3 = '그는 첫날 사무실 동료들에게 자기소개를 했어요.', example_en_4 = 'There is a common greeting area outside the office.', example_ko_4 = '사무실 밖에 공용 인사 공간이 있어요.', example_en_5 = 'She decorated the office entrance to welcome the new team.', example_ko_5 = '그녀는 새 팀을 환영하기 위해 사무실 입구를 꾸몄어요.' WHERE id = 'w_greeting_A2_26';
UPDATE words SET example_en_2 = 'She introduced the new colleague to the rest of the team.', example_ko_2 = '그녀는 새 동료를 나머지 팀원들에게 소개했어요.', example_en_3 = 'He is a colleague I met at a conference last year.', example_ko_3 = '그는 작년 컨퍼런스에서 만난 동료예요.', example_en_4 = 'My colleague kindly showed me around on my first day.', example_ko_4 = '동료가 첫날에 친절하게 안내해 줬어요.', example_en_5 = 'She waved to her colleague across the open-plan office.', example_ko_5 = '그녀는 오픈형 사무실 너머의 동료에게 손을 흔들었어요.' WHERE id = 'w_greeting_A2_27';
UPDATE words SET example_en_2 = 'Her neighbor always says good morning with a big smile.', example_ko_2 = '그녀의 이웃은 항상 환한 미소로 좋은 아침이에요라고 인사해요.', example_en_3 = 'Being friendly with your neighbors makes life easier.', example_ko_3 = '이웃에게 친근하게 대하면 생활이 더 편해요.', example_en_4 = 'He waved to his neighbor as he left for work.', example_ko_4 = '그는 출근하며 이웃에게 손을 흔들었어요.', example_en_5 = 'She baked cookies and introduced herself to her new neighbor.', example_ko_5 = '그녀는 쿠키를 구워 새 이웃에게 자기소개를 했어요.' WHERE id = 'w_greeting_A2_28';
UPDATE words SET example_en_2 = 'We both arrived at the same time — what a coincidence!', example_ko_2 = '우리 둘 다 동시에 도착했네요. 정말 우연이에요!', example_en_3 = 'They work in the same company but had never met before.', example_ko_3 = '그들은 같은 회사에 다니는데 한 번도 만난 적이 없었어요.', example_en_4 = 'We share the same taste in coffee — let''s grab one sometime.', example_ko_4 = '커피 취향이 같네요. 언제 한 번 같이 마셔요.', example_en_5 = 'She noticed they had the same hometown during the introduction.', example_ko_5 = '자기소개 중에 고향이 같다는 것을 알았어요.' WHERE id = 'w_greeting_A2_29';
UPDATE words SET example_en_2 = 'Please call me by my nickname — it''s easier.', example_ko_2 = '닉네임으로 불러 주세요. 그게 더 편해요.', example_en_3 = 'She asked what she should call him at work.', example_ko_3 = '그녀는 직장에서 어떻게 불러야 하는지 물었어요.', example_en_4 = 'Everyone calls him by his first name in this office.', example_ko_4 = '이 사무실에서 모두 그를 이름으로 불러요.', example_en_5 = '"You can call me Jina," she said with a smile.', example_ko_5 = '"지나라고 불러 주세요," 그녀가 미소를 지으며 말했어요.' WHERE id = 'w_greeting_A2_30';
UPDATE words SET example_en_2 = 'We are the same age — when is your birthday?', example_ko_2 = '우리 나이가 같네요. 생일이 언제예요?', example_en_3 = 'She asked his age while getting to know each other.', example_ko_3 = '서로 알아가는 과정에서 그녀는 나이를 물었어요.', example_en_4 = 'In Korean culture, age is often discussed early in introductions.', example_ko_4 = '한국 문화에서는 자기소개 초반에 나이를 자주 이야기해요.', example_en_5 = 'They laughed when they realized they were the same age.', example_ko_5 = '같은 나이라는 것을 알고 그들은 웃었어요.' WHERE id = 'w_greeting_A2_31';
UPDATE words SET example_en_2 = 'Do you have any hobbies you like to do on weekends?', example_ko_2 = '주말에 즐기는 취미가 있어요?', example_en_3 = 'Sharing hobbies is a great way to connect with someone.', example_ko_3 = '취미를 공유하는 것은 누군가와 친해지는 좋은 방법이에요.', example_en_4 = 'He mentioned his hobby is photography when they first met.', example_ko_4 = '처음 만났을 때 그는 취미가 사진 찍기라고 했어요.', example_en_5 = 'They discovered a shared hobby within minutes of meeting.', example_ko_5 = '만난 지 몇 분 만에 공통 취미를 발견했어요.' WHERE id = 'w_greeting_A2_32';
UPDATE words SET example_en_2 = 'She joined the company three weeks ago.', example_ko_2 = '그녀는 3주 전에 회사에 합류했어요.', example_en_3 = 'He was excited to join the new study group.', example_ko_3 = '그는 새 스터디 그룹에 합류하게 되어 설렜어요.', example_en_4 = 'She asked if it was okay to join the conversation.', example_ko_4 = '대화에 참여해도 되는지 그녀가 물었어요.', example_en_5 = 'They welcomed him warmly when he joined the team.', example_ko_5 = '그가 팀에 합류했을 때 모두 따뜻하게 맞이했어요.' WHERE id = 'w_greeting_A2_33';
UPDATE words SET example_en_2 = 'I have been wanting to meet you for a long time.', example_ko_2 = '오랫동안 만나 뵙고 싶었어요.', example_en_3 = 'She has been meaning to introduce herself to the new team.', example_ko_3 = '새 팀에 자기소개를 하려고 생각해왔어요.', example_en_4 = 'He had been hoping to run into her at the conference.', example_ko_4 = '컨퍼런스에서 그녀를 만나길 바라고 있었어요.', example_en_5 = 'It has been a while since we last spoke.', example_ko_5 = '마지막으로 이야기를 나눈 지 꽤 됐네요.' WHERE id = 'w_greeting_A2_34';
UPDATE words SET example_en_2 = 'She was wondering if the new person had settled in yet.', example_ko_2 = '새로운 분이 이미 적응했는지 궁금했어요.', example_en_3 = 'He was wondering how to break the ice at the event.', example_ko_3 = '행사에서 어떻게 분위기를 풀어야 할지 궁금했어요.', example_en_4 = 'I was wondering if you would like to join us for lunch.', example_ko_4 = '점심에 함께하시겠는지 여쭤보고 싶었어요.', example_en_5 = 'She wondered whether to introduce herself first or wait.', example_ko_5 = '먼저 자기소개를 해야 할지 기다려야 할지 궁금했어요.' WHERE id = 'w_greeting_A2_35';

