UPDATE words SET example_en_2 = 'She is a business acquaintance I met at a seminar.', example_ko_2 = '그녀는 세미나에서 만난 비즈니스 지인이에요.', example_en_3 = 'He is not a close friend — just an acquaintance from work.', example_ko_3 = '그는 친한 친구가 아니라 직장에서 알게 된 지인이에요.', example_en_4 = 'She greeted the acquaintance with a polite nod.', example_ko_4 = '그녀는 지인에게 정중하게 고개를 끄덕여 인사했어요.', example_en_5 = 'Over time, the acquaintance became a close friend.', example_ko_5 = '시간이 지나면서 지인이 친한 친구가 됐어요.' WHERE id = 'w_greeting_B1_01';
UPDATE words SET example_en_2 = 'His calm impression put everyone at ease from the start.', example_ko_2 = '그의 차분한 인상 덕분에 처음부터 모두가 편안해졌어요.', example_en_3 = 'She made a lasting impression with her confident greeting.', example_ko_3 = '그녀는 자신감 있는 인사로 오래도록 기억에 남는 인상을 남겼어요.', example_en_4 = 'First impressions matter a lot in professional settings.', example_ko_4 = '전문적인 환경에서는 첫인상이 매우 중요해요.', example_en_5 = 'He left a positive impression on everyone he met.', example_ko_5 = '그는 만나는 모든 사람에게 좋은 인상을 남겼어요.' WHERE id = 'w_greeting_B1_02';
UPDATE words SET example_en_2 = 'Networking at events is a great way to meet new people.', example_ko_2 = '행사에서 네트워킹은 새로운 사람들을 만나는 좋은 방법이에요.', example_en_3 = 'She built her career through consistent networking.', example_ko_3 = '그녀는 꾸준한 네트워킹을 통해 커리어를 쌓았어요.', example_en_4 = 'He attended the networking event to expand his contacts.', example_ko_4 = '그는 인맥을 넓히기 위해 네트워킹 행사에 참석했어요.', example_en_5 = 'Good networking skills open many professional doors.', example_ko_5 = '좋은 네트워킹 능력은 많은 직업적 기회의 문을 열어줘요.' WHERE id = 'w_greeting_B1_03';
UPDATE words SET example_en_2 = 'She thanked everyone with great courtesy at the end.', example_ko_2 = '그녀는 마지막에 모두에게 큰 예의로 감사를 표했어요.', example_en_3 = 'He showed courtesy by listening carefully before responding.', example_ko_3 = '그는 대답하기 전에 주의 깊게 듣는 예의를 보였어요.', example_en_4 = 'Common courtesy means greeting people when you enter a room.', example_ko_4 = '기본 예의란 방에 들어갈 때 인사하는 거예요.', example_en_5 = 'Professional courtesy is especially important in first meetings.', example_ko_5 = '전문적인 예의는 특히 첫 만남에서 중요해요.' WHERE id = 'w_greeting_B1_04';
UPDATE words SET example_en_2 = 'They built a strong rapport after just one conversation.', example_ko_2 = '단 한 번의 대화 후에 강한 유대감을 쌓았어요.', example_en_3 = 'Building rapport with clients is key in customer service.', example_ko_3 = '고객 서비스에서 고객과 유대감을 쌓는 것이 핵심이에요.', example_en_4 = 'She found it easy to build rapport with strangers.', example_ko_4 = '그녀는 낯선 사람과도 쉽게 유대감을 쌓았어요.', example_en_5 = 'Good rapport starts with a genuine greeting.', example_ko_5 = '좋은 유대감은 진심 어린 인사에서 시작돼요.' WHERE id = 'w_greeting_B1_05';
UPDATE words SET example_en_2 = 'The workshop started with a fun icebreaker game.', example_ko_2 = '워크샵은 재미있는 아이스브레이커 게임으로 시작됐어요.', example_en_3 = 'She suggested a quick icebreaker to help people relax.', example_ko_3 = '그녀는 사람들이 긴장을 풀도록 간단한 아이스브레이커를 제안했어요.', example_en_4 = 'A good icebreaker can turn strangers into friends.', example_ko_4 = '좋은 아이스브레이커는 낯선 사람들을 친구로 만들 수 있어요.', example_en_5 = 'He used a classic icebreaker to open the networking session.', example_ko_5 = '그는 네트워킹 세션을 열기 위해 고전적인 아이스브레이커를 사용했어요.' WHERE id = 'w_greeting_B1_06';
UPDATE words SET example_en_2 = 'She received a kind compliment that made her smile.', example_ko_2 = '그녀는 미소 짓게 만드는 친절한 칭찬을 받았어요.', example_en_3 = 'He paid her a compliment on her presentation skills.', example_ko_3 = '그는 그녀의 발표 능력을 칭찬했어요.', example_en_4 = 'Starting with a compliment is a great way to warm up a conversation.', example_ko_4 = '칭찬으로 시작하는 것은 대화를 부드럽게 풀어가는 좋은 방법이에요.', example_en_5 = 'She always gives a genuine compliment when she meets someone.', example_ko_5 = '그녀는 누군가를 만날 때 항상 진심 어린 칭찬을 해요.' WHERE id = 'w_greeting_B1_07';
UPDATE words SET example_en_2 = 'They met for the first time at the company reception.', example_ko_2 = '그들은 회사 환영 행사에서 처음 만났어요.', example_en_3 = 'The reception was the perfect place to introduce yourself.', example_ko_3 = '환영 행사는 자기소개를 하기에 완벽한 장소였어요.', example_en_4 = 'She greeted the new hires at the welcome reception.', example_ko_4 = '그녀는 환영 행사에서 신입 사원들을 맞이했어요.', example_en_5 = 'The reception hall was filled with warm greetings.', example_ko_5 = '환영 행사장은 따뜻한 인사로 가득했어요.' WHERE id = 'w_greeting_B1_08';
UPDATE words SET example_en_2 = 'Korean hospitality made her feel welcome right away.', example_ko_2 = '한국의 환대 덕분에 그녀는 바로 환영받는 느낌이었어요.', example_en_3 = 'Their hospitality was evident from the moment we arrived.', example_ko_3 = '우리가 도착한 순간부터 그들의 환대가 느껴졌어요.', example_en_4 = 'He showed genuine hospitality to every single guest.', example_ko_4 = '그는 모든 손님에게 진심 어린 환대를 보였어요.', example_en_5 = 'Warm hospitality is one of the best first impressions you can make.', example_ko_5 = '따뜻한 환대는 남길 수 있는 최고의 첫인상 중 하나예요.' WHERE id = 'w_greeting_B1_09';
UPDATE words SET example_en_2 = 'They discovered they had a mutual interest in hiking.', example_ko_2 = '그들은 하이킹에 대한 공통 관심사를 발견했어요.', example_en_3 = 'She found that they had several mutual friends in common.', example_ko_3 = '그녀는 공통 친구가 여러 명 있다는 것을 알았어요.', example_en_4 = 'A mutual respect made the introduction go very smoothly.', example_ko_4 = '서로에 대한 존중 덕분에 소개가 매우 순조롭게 진행됐어요.', example_en_5 = 'The two teams found mutual ground during the welcome dinner.', example_ko_5 = '두 팀은 환영 만찬에서 공통점을 찾았어요.' WHERE id = 'w_greeting_B1_10';
UPDATE words SET example_en_2 = 'She approached the stranger and introduced herself.', example_ko_2 = '그녀는 낯선 사람에게 다가가 자기소개를 했어요.', example_en_3 = 'He approached the meeting with an open mind.', example_ko_3 = '그는 열린 마음으로 만남에 임했어요.', example_en_4 = 'Don''t be afraid to approach someone new at an event.', example_ko_4 = '행사에서 새로운 사람에게 다가가는 것을 두려워하지 마세요.', example_en_5 = 'She approached the group with a warm smile.', example_ko_5 = '그녀는 따뜻한 미소로 그룹에 다가갔어요.' WHERE id = 'w_greeting_B1_11';
UPDATE words SET example_en_2 = 'They had a pleasant conversation during the coffee break.', example_ko_2 = '커피 브레이크 동안 즐거운 대화를 나눴어요.', example_en_3 = 'She started a conversation with the person sitting next to her.', example_ko_3 = '그녀는 옆에 앉은 사람과 대화를 시작했어요.', example_en_4 = 'Good conversation skills make introductions much easier.', example_ko_4 = '좋은 대화 능력은 소개를 훨씬 쉽게 만들어요.', example_en_5 = 'He kept the conversation light and friendly at first.', example_ko_5 = '그는 처음에는 대화를 가볍고 친근하게 유지했어요.' WHERE id = 'w_greeting_B1_12';
UPDATE words SET example_en_2 = 'They exchanged contact details after the event.', example_ko_2 = '행사 후에 그들은 연락처를 교환했어요.', example_en_3 = 'She exchanged a warm greeting with each guest.', example_ko_3 = '그녀는 각 손님과 따뜻한 인사를 나눴어요.', example_en_4 = 'It is common to exchange business cards at conferences.', example_ko_4 = '컨퍼런스에서 명함을 교환하는 것은 흔한 일이에요.', example_en_5 = 'They exchanged pleasantries before getting down to business.', example_ko_5 = '그들은 업무를 시작하기 전에 가볍게 인사를 나눴어요.' WHERE id = 'w_greeting_B1_13';
UPDATE words SET example_en_2 = 'She gave a brief overview of her background during the intro.', example_ko_2 = '소개 중에 자신의 배경에 대해 간략하게 설명했어요.', example_en_3 = 'Understanding someone''s background helps build connection.', example_ko_3 = '상대방의 배경을 이해하는 것은 유대감을 쌓는 데 도움이 돼요.', example_en_4 = 'He shared his professional background during the networking event.', example_ko_4 = '그는 네트워킹 행사에서 자신의 직업적 배경을 공유했어요.', example_en_5 = 'She asked about his background to find common ground.', example_ko_5 = '그녀는 공통점을 찾기 위해 그의 배경에 대해 물었어요.' WHERE id = 'w_greeting_B1_14';
UPDATE words SET example_en_2 = 'She was thrilled to reconnect with her old mentor.', example_ko_2 = '그녀는 오래된 멘토와 다시 연락이 닿아 감격했어요.', example_en_3 = 'The reunion was a chance to reconnect after many years.', example_ko_3 = '동창회는 수년 만에 다시 연결되는 기회였어요.', example_en_4 = 'He reached out to reconnect with former colleagues.', example_ko_4 = '그는 예전 동료들과 다시 연락하기 위해 연락을 취했어요.', example_en_5 = 'They used the conference to reconnect with old contacts.', example_ko_5 = '그들은 컨퍼런스를 이용해 오래된 지인들과 다시 연결됐어요.' WHERE id = 'w_greeting_B1_15';
UPDATE words SET example_en_2 = 'A slight bow is a polite gesture in Korean culture.', example_ko_2 = '가볍게 고개를 숙이는 것은 한국 문화에서 예의 바른 제스처예요.', example_en_3 = 'Her welcoming gesture made the new member feel at ease.', example_ko_3 = '그녀의 환영하는 제스처 덕분에 새 멤버가 편안해졌어요.', example_en_4 = 'He made a small gesture to show he recognized her.', example_ko_4 = '그는 그녀를 알아봤다는 것을 보여주는 작은 제스처를 했어요.', example_en_5 = 'Simple gestures like a nod or wave go a long way.', example_ko_5 = '고개 끄덕임이나 손짓 같은 간단한 제스처도 큰 역할을 해요.' WHERE id = 'w_greeting_B1_16';
UPDATE words SET example_en_2 = 'Their bond grew stronger every time they met.', example_ko_2 = '만날 때마다 그들의 유대가 더 강해졌어요.', example_en_3 = 'The team developed a strong bond after working together.', example_ko_3 = '팀은 함께 일하며 강한 유대를 형성했어요.', example_en_4 = 'She felt an instant bond with the person she met.', example_ko_4 = '그녀는 만난 사람과 즉각적인 유대감을 느꼈어요.', example_en_5 = 'A warm greeting is the first step to forming a real bond.', example_ko_5 = '따뜻한 인사는 진정한 유대를 형성하는 첫 걸음이에요.' WHERE id = 'w_greeting_B1_17';
UPDATE words SET example_en_2 = 'She felt instant recognition when she heard his name.', example_ko_2 = '그의 이름을 들었을 때 즉각적인 알아봄이 있었어요.', example_en_3 = 'His face showed recognition when she walked in.', example_ko_3 = '그녀가 들어왔을 때 그의 얼굴에 알아보는 기색이 보였어요.', example_en_4 = 'The recognition on her face made him smile.', example_ko_4 = '그녀의 얼굴에 나타난 알아보는 표정이 그를 미소 짓게 했어요.', example_en_5 = 'She appreciated the warm recognition she received.', example_ko_5 = '그녀는 받은 따뜻한 인정에 감사했어요.' WHERE id = 'w_greeting_B1_18';
UPDATE words SET example_en_2 = 'Building a good relationship starts with a genuine introduction.', example_ko_2 = '좋은 관계를 쌓는 것은 진심 어린 소개에서 시작돼요.', example_en_3 = 'She values every relationship she has formed through networking.', example_ko_3 = '그녀는 네트워킹을 통해 형성된 모든 관계를 소중히 여겨요.', example_en_4 = 'He hoped the first meeting would begin a strong relationship.', example_ko_4 = '그는 첫 만남이 강한 관계의 시작이 되길 바랐어요.', example_en_5 = 'A warm greeting is the foundation of any good relationship.', example_ko_5 = '따뜻한 인사는 모든 좋은 관계의 토대예요.' WHERE id = 'w_greeting_B1_19';
UPDATE words SET example_en_2 = 'She introduced her colleague from the design team.', example_ko_2 = '그녀는 디자인 팀 동료를 소개했어요.', example_en_3 = 'He asked his colleague to help break the ice.', example_ko_3 = '그는 동료에게 분위기를 풀어달라고 부탁했어요.', example_en_4 = 'His colleague greeted the client with great warmth.', example_ko_4 = '그의 동료는 고객을 정말 따뜻하게 맞이했어요.', example_en_5 = 'Treating colleagues with respect sets a good tone.', example_ko_5 = '동료를 존중하며 대하면 좋은 분위기가 형성돼요.' WHERE id = 'w_greeting_B1_20';
UPDATE words SET example_en_2 = 'They quickly found common ground in their love of travel.', example_ko_2 = '그들은 여행을 좋아한다는 공통점을 금세 찾았어요.', example_en_3 = 'Finding common ground makes a first meeting much easier.', example_ko_3 = '공통점을 찾으면 첫 만남이 훨씬 쉬워요.', example_en_4 = 'She always looks for common ground when meeting new people.', example_ko_4 = '그녀는 새로운 사람을 만날 때 항상 공통점을 찾아요.', example_en_5 = 'They used their common ground to build a lasting friendship.', example_ko_5 = '그들은 공통점을 바탕으로 오래가는 우정을 쌓았어요.' WHERE id = 'w_greeting_B1_21';
UPDATE words SET example_en_2 = 'The reunion was filled with warm hugs and laughter.', example_ko_2 = '동창회는 따뜻한 포옹과 웃음으로 가득했어요.', example_en_3 = 'She looked forward to the class reunion every year.', example_ko_3 = '그녀는 매년 학교 동창회를 기대했어요.', example_en_4 = 'The family reunion was the perfect chance to reconnect.', example_ko_4 = '가족 모임은 다시 연결되는 완벽한 기회였어요.', example_en_5 = 'He was moved by the warmth of the reunion.', example_ko_5 = '그는 재회의 따뜻함에 감동받았어요.' WHERE id = 'w_greeting_B1_22';
UPDATE words SET example_en_2 = 'He is very outgoing and never hesitates to introduce himself.', example_ko_2 = '그는 매우 외향적이어서 자기소개를 망설이지 않아요.', example_en_3 = 'An outgoing personality helps you thrive at networking events.', example_ko_3 = '외향적인 성격은 네트워킹 행사에서 빛을 발하게 해줘요.', example_en_4 = 'She became more outgoing after joining the drama club.', example_ko_4 = '연극 동아리에 가입한 후 그녀는 더 외향적이 됐어요.', example_en_5 = 'His outgoing nature made everyone feel welcome immediately.', example_ko_5 = '그의 외향적인 성격 덕분에 모두가 즉시 환영받는 느낌을 받았어요.' WHERE id = 'w_greeting_B1_23';
UPDATE words SET example_en_2 = 'Please use my first name — it makes things less formal.', example_ko_2 = '이름으로 불러 주세요. 덜 격식적으로 느껴지거든요.', example_en_3 = 'She introduced herself by first name at the casual event.', example_ko_3 = '그녀는 격식 없는 행사에서 이름으로 자기소개를 했어요.', example_en_4 = 'In this office, we are all on a first name basis.', example_ko_4 = '이 사무실에서는 모두 이름으로 부르는 사이예요.', example_en_5 = 'He asked if it was okay to use her first name.', example_ko_5 = '그는 이름으로 불러도 되는지 물었어요.' WHERE id = 'w_greeting_B1_24';
UPDATE words SET example_en_2 = 'The friendly atmosphere made it easy to start conversations.', example_ko_2 = '친근한 분위기 덕분에 대화를 시작하기 쉬웠어요.', example_en_3 = 'She worked to create a welcoming atmosphere at the event.', example_ko_3 = '그녀는 행사에서 환영하는 분위기를 만들기 위해 노력했어요.', example_en_4 = 'The warm atmosphere helped everyone feel comfortable.', example_ko_4 = '따뜻한 분위기 덕분에 모두가 편안함을 느꼈어요.', example_en_5 = 'A positive atmosphere starts with a genuine greeting.', example_ko_5 = '긍정적인 분위기는 진심 어린 인사에서 시작돼요.' WHERE id = 'w_greeting_B1_25';
UPDATE words SET example_en_2 = 'Her genuine interest in people makes everyone feel special.', example_ko_2 = '사람들에 대한 그녀의 진심 어린 관심이 모두를 특별하게 느끼게 해요.', example_en_3 = 'A genuine compliment is always better than a forced one.', example_ko_3 = '진심 어린 칭찬이 억지 칭찬보다 항상 더 좋아요.', example_en_4 = 'He showed genuine curiosity when asking about her work.', example_ko_4 = '그는 그녀의 일에 대해 물어볼 때 진심 어린 호기심을 보였어요.', example_en_5 = 'Genuine warmth is the best tool when meeting someone new.', example_ko_5 = '새로운 사람을 만날 때 진심 어린 따뜻함이 최고의 도구예요.' WHERE id = 'w_greeting_B1_26';
UPDATE words SET example_en_2 = 'It is important to be respectful when greeting elders.', example_ko_2 = '어른에게 인사할 때 존중하는 태도를 갖추는 것이 중요해요.', example_en_3 = 'She is always respectful and polite to everyone she meets.', example_ko_3 = '그녀는 만나는 모든 사람에게 항상 존중하고 예의 바르게 대해요.', example_en_4 = 'He greeted the senior staff in a respectful manner.', example_ko_4 = '그는 선임 직원들에게 존중하는 태도로 인사했어요.', example_en_5 = 'Being respectful in greetings reflects good character.', example_ko_5 = '인사에서 존중하는 태도는 좋은 인품을 보여줘요.' WHERE id = 'w_greeting_B1_27';
UPDATE words SET example_en_2 = 'His warmth immediately put the nervous newcomer at ease.', example_ko_2 = '그의 따뜻함이 긴장한 신입을 바로 편안하게 했어요.', example_en_3 = 'She greeted the guests with genuine warmth.', example_ko_3 = '그녀는 진심 어린 따뜻함으로 손님들을 맞이했어요.', example_en_4 = 'His warmth and openness made him easy to approach.', example_ko_4 = '그의 따뜻함과 개방성 덕분에 그에게 다가가기 쉬웠어요.', example_en_5 = 'Warmth in a greeting can leave a lasting impression.', example_ko_5 = '인사에서의 따뜻함은 오래도록 기억에 남는 인상을 남길 수 있어요.' WHERE id = 'w_greeting_B1_28';
UPDATE words SET example_en_2 = 'She mentioned that they had worked together before.', example_ko_2 = '그녀는 전에 함께 일한 적이 있다고 언급했어요.', example_en_3 = 'He mentioned a shared contact to break the ice.', example_ko_3 = '그는 분위기를 풀기 위해 공통 지인을 언급했어요.', example_en_4 = 'She briefly mentioned her background before asking about his.', example_ko_4 = '그녀는 그의 배경을 묻기 전에 자신의 배경을 간략히 언급했어요.', example_en_5 = 'He mentioned hearing great things about her work.', example_ko_5 = '그는 그녀의 일에 대해 좋은 이야기를 들었다고 언급했어요.' WHERE id = 'w_greeting_B1_29';
UPDATE words SET example_en_2 = 'They met on a formal occasion and became good friends.', example_ko_2 = '그들은 격식 있는 자리에서 만나 좋은 친구가 됐어요.', example_en_3 = 'This is a great occasion to make new connections.', example_ko_3 = '이 자리는 새로운 인맥을 만들기에 좋은 기회예요.', example_en_4 = 'She used the occasion to introduce herself to the team.', example_ko_4 = '그녀는 그 자리를 팀에 자기소개 하는 기회로 삼았어요.', example_en_5 = 'On this occasion, we welcome a very special guest.', example_ko_5 = '이 자리에서 특별한 손님을 환영합니다.' WHERE id = 'w_greeting_B1_30';
UPDATE words SET example_en_2 = 'She has been in the hospitality industry for ten years.', example_ko_2 = '그녀는 10년 동안 서비스 업계에서 일해왔어요.', example_en_3 = 'He networked across multiple industries at the event.', example_ko_3 = '그는 행사에서 여러 업계를 넘나들며 네트워킹했어요.', example_en_4 = 'Which industry are you in? I work in finance.', example_ko_4 = '어떤 업계에 계세요? 저는 금융 쪽이에요.', example_en_5 = 'Meeting people from different industries is eye-opening.', example_ko_5 = '다양한 업계의 사람들을 만나는 것은 시야를 넓혀줘요.' WHERE id = 'w_greeting_B1_31';
UPDATE words SET example_en_2 = 'She gave him her contact details at the end of the meeting.', example_ko_2 = '그녀는 회의 마지막에 그에게 연락처를 줬어요.', example_en_3 = 'He added her as a contact after the networking event.', example_ko_3 = '그는 네트워킹 행사 후에 그녀를 연락처에 추가했어요.', example_en_4 = 'Stay in contact — it''s important for professional growth.', example_ko_4 = '연락을 유지하세요. 직업적 성장에 중요해요.', example_en_5 = 'She preferred to make contact in person rather than online.', example_ko_5 = '그녀는 온라인보다 직접 연락하는 것을 더 좋아했어요.' WHERE id = 'w_greeting_B1_32';
UPDATE words SET example_en_2 = 'She always follows up after a first meeting with a short email.', example_ko_2 = '그녀는 첫 만남 후 항상 간단한 이메일로 후속 연락을 해요.', example_en_3 = 'He followed up to thank her for the introduction.', example_ko_3 = '그는 소개해 준 것에 감사하기 위해 후속 연락을 했어요.', example_en_4 = 'A quick follow up shows that you value the connection.', example_ko_4 = '간단한 후속 연락은 그 인연을 소중히 여긴다는 것을 보여줘요.', example_en_5 = 'Don''t forget to follow up after the event.', example_ko_5 = '행사 후에 후속 연락하는 것을 잊지 마세요.' WHERE id = 'w_greeting_B1_33';
UPDATE words SET example_en_2 = 'Their first meeting was truly memorable for both of them.', example_ko_2 = '그들의 첫 만남은 두 사람 모두에게 정말 기억에 남는 것이었어요.', example_en_3 = 'She made the introduction memorable with a personal touch.', example_ko_3 = '그녀는 개인적인 감성을 더해 소개를 기억에 남게 했어요.', example_en_4 = 'A memorable greeting can open many doors.', example_ko_4 = '기억에 남는 인사는 많은 문을 열 수 있어요.', example_en_5 = 'His warm manner made every meeting memorable.', example_ko_5 = '그의 따뜻한 태도는 모든 만남을 기억에 남게 만들었어요.' WHERE id = 'w_greeting_B1_34';
UPDATE words SET example_en_2 = 'A sincere greeting is always more effective than a scripted one.', example_ko_2 = '진심 어린 인사는 항상 준비된 인사보다 더 효과적이에요.', example_en_3 = 'She gave him a sincere thank you at the end.', example_ko_3 = '그녀는 마지막에 그에게 진심 어린 감사를 표했어요.', example_en_4 = 'A sincere smile is the best way to start any meeting.', example_ko_4 = '진심 어린 미소는 어떤 만남이든 시작하는 최고의 방법이에요.', example_en_5 = 'He appreciated her sincere interest in his background.', example_ko_5 = '그는 자신의 배경에 대한 그녀의 진심 어린 관심에 감사했어요.' WHERE id = 'w_greeting_B1_35';

