UPDATE words SET example_en_2 = 'Understanding local etiquette helps you make a good impression.', example_ko_2 = '현지 예절을 이해하면 좋은 인상을 남기는 데 도움이 돼요.', example_en_3 = 'Business etiquette includes knowing when to bow or shake hands.', example_ko_3 = '비즈니스 예절에는 언제 절하거나 악수해야 하는지 아는 것이 포함돼요.', example_en_4 = 'She studied greeting etiquette before her overseas trip.', example_ko_4 = '그녀는 해외 여행 전에 인사 예절을 공부했어요.', example_en_5 = 'He followed proper etiquette when introduced to the senior manager.', example_ko_5 = '그는 선임 매니저에게 소개받을 때 적절한 예절을 따랐어요.' WHERE id = 'w_greeting_B2_01';
UPDATE words SET example_en_2 = 'His professional demeanor made everyone trust him instantly.', example_ko_2 = '그의 전문적인 태도 덕분에 모두가 즉시 그를 신뢰했어요.', example_en_3 = 'She maintained a friendly demeanor throughout the meeting.', example_ko_3 = '그녀는 회의 내내 친근한 태도를 유지했어요.', example_en_4 = 'His demeanor changed when he recognized an old friend.', example_ko_4 = '오래된 친구를 알아봤을 때 그의 태도가 바뀌었어요.', example_en_5 = 'A confident demeanor signals social ease.', example_ko_5 = '자신감 있는 태도는 사교적 편안함을 보여줘요.' WHERE id = 'w_greeting_B2_02';
UPDATE words SET example_en_2 = 'She maintained decorum even in the most relaxed gatherings.', example_ko_2 = '그녀는 가장 편안한 모임에서도 예의범절을 지켰어요.', example_en_3 = 'Decorum is especially important when meeting clients for the first time.', example_ko_3 = '고객을 처음 만날 때 예의범절이 특히 중요해요.', example_en_4 = 'He expected a high level of decorum at the formal dinner.', example_ko_4 = '그는 공식 만찬에서 높은 수준의 예의범절을 기대했어요.', example_en_5 = 'She was known for her impeccable decorum in every situation.', example_ko_5 = '그녀는 모든 상황에서 흠잡을 데 없는 예의범절로 유명했어요.' WHERE id = 'w_greeting_B2_03';
UPDATE words SET example_en_2 = 'A formal salutation is expected in diplomatic circles.', example_ko_2 = '외교 분야에서는 격식 있는 인사말이 기대돼요.', example_en_3 = 'He opened the letter with a polite salutation.', example_ko_3 = '그는 편지를 정중한 인사말로 시작했어요.', example_en_4 = 'She offered a respectful salutation with a slight bow.', example_ko_4 = '그녀는 가볍게 고개를 숙여 정중한 인사를 했어요.', example_en_5 = 'Knowing the correct salutation is important in formal correspondence.', example_ko_5 = '공식 서한에서 올바른 인사말을 아는 것이 중요해요.' WHERE id = 'w_greeting_B2_04';
UPDATE words SET example_en_2 = 'Her approachable manner encouraged others to speak first.', example_ko_2 = '그녀의 친근한 태도가 다른 사람들이 먼저 말을 걸도록 했어요.', example_en_3 = 'He made himself approachable by smiling and using open body language.', example_ko_3 = '그는 미소와 열린 몸짓으로 다가가기 쉬운 사람이 됐어요.', example_en_4 = 'Being approachable is one of the most valuable social skills.', example_ko_4 = '다가가기 쉬운 사람이 되는 것은 가장 소중한 사교적 능력 중 하나예요.', example_en_5 = 'She was described as warm and approachable by all who met her.', example_ko_5 = '그녀는 만나는 모든 사람들에게 따뜻하고 다가가기 쉬운 사람으로 묘사됐어요.' WHERE id = 'w_greeting_B2_05';
UPDATE words SET example_en_2 = 'She handled the awkward introduction in a diplomatic way.', example_ko_2 = '그녀는 어색한 소개를 외교적으로 처리했어요.', example_en_3 = 'He was diplomatic when asking how to pronounce her name.', example_ko_3 = '그는 이름 발음을 물을 때 외교적이었어요.', example_en_4 = 'A diplomatic greeting avoids offending anyone.', example_ko_4 = '외교적인 인사는 누구도 불쾌하게 하지 않아요.', example_en_5 = 'She was praised for her diplomatic approach to every interaction.', example_ko_5 = '그녀는 모든 상호 작용에서 외교적인 접근으로 칭찬을 받았어요.' WHERE id = 'w_greeting_B2_06';
UPDATE words SET example_en_2 = 'He knew the tactful way to introduce himself without seeming pushy.', example_ko_2 = '그는 지나치게 적극적으로 보이지 않으면서 요령 있게 자기소개하는 방법을 알았어요.', example_en_3 = 'A tactful greeting can defuse tension in a difficult meeting.', example_ko_3 = '요령 있는 인사는 어려운 회의에서 긴장을 풀 수 있어요.', example_en_4 = 'She was tactful when correcting the mispronunciation of her name.', example_ko_4 = '그녀는 이름 잘못 발음을 정정할 때 요령 있게 행동했어요.', example_en_5 = 'Being tactful in greetings shows emotional intelligence.', example_ko_5 = '인사에서 요령 있게 행동하는 것은 감성 지능을 보여줘요.' WHERE id = 'w_greeting_B2_07';
UPDATE words SET example_en_2 = 'Her endearing habit of remembering everyone''s name was well-known.', example_ko_2 = '모든 사람의 이름을 기억하는 그녀의 정겨운 습관은 잘 알려져 있었어요.', example_en_3 = 'His endearing smile made everyone feel instantly welcome.', example_ko_3 = '그의 정겨운 미소 덕분에 모두가 즉시 환영받는 느낌을 받았어요.', example_en_4 = 'There was something endearing about the way she greeted old friends.', example_ko_4 = '그녀가 오래된 친구들에게 인사하는 방식에는 정겨운 무언가가 있었어요.', example_en_5 = 'His endearing personality made first meetings feel effortless.', example_ko_5 = '그의 정겨운 성격 덕분에 처음 만남이 수월하게 느껴졌어요.' WHERE id = 'w_greeting_B2_08';
UPDATE words SET example_en_2 = 'Her charismatic presence filled the room the moment she walked in.', example_ko_2 = '그녀가 들어오는 순간 그녀의 카리스마 넘치는 존재감이 방을 가득 채웠어요.', example_en_3 = 'His charismatic introduction drew applause from the audience.', example_ko_3 = '그의 카리스마 넘치는 소개가 청중의 박수를 받았어요.', example_en_4 = 'Being charismatic helps you connect with people quickly.', example_ko_4 = '카리스마가 있으면 사람들과 빠르게 연결되는 데 도움이 돼요.', example_en_5 = 'She greeted the panel in a charismatic and confident way.', example_ko_5 = '그녀는 카리스마 있고 자신감 있게 패널들에게 인사했어요.' WHERE id = 'w_greeting_B2_09';
UPDATE words SET example_en_2 = 'The congenial group made new members feel welcome instantly.', example_ko_2 = '마음이 맞는 그룹 덕분에 신입 멤버들이 즉시 환영받는 느낌이었어요.', example_en_3 = 'She found the team very congenial from the first meeting.', example_ko_3 = '그녀는 처음 만남부터 팀이 매우 마음에 맞는다고 느꼈어요.', example_en_4 = 'He was a congenial host who made everyone feel at home.', example_ko_4 = '그는 모든 사람이 편안함을 느끼게 해주는 마음 좋은 호스트였어요.', example_en_5 = 'The congenial atmosphere made networking feel natural.', example_ko_5 = '마음 맞는 분위기 덕분에 네트워킹이 자연스럽게 느껴졌어요.' WHERE id = 'w_greeting_B2_10';
UPDATE words SET example_en_2 = 'She was articulate and clear when explaining her background.', example_ko_2 = '그녀는 자신의 배경을 설명할 때 표현이 명확했어요.', example_en_3 = 'Being articulate makes a strong impression in introductions.', example_ko_3 = '표현이 명확하면 소개에서 강한 인상을 남겨요.', example_en_4 = 'He gave an articulate and concise overview of his experience.', example_ko_4 = '그는 자신의 경험을 명확하고 간결하게 설명했어요.', example_en_5 = 'An articulate greeting shows confidence and preparation.', example_ko_5 = '명확한 인사는 자신감과 준비성을 보여줘요.' WHERE id = 'w_greeting_B2_11';
UPDATE words SET example_en_2 = 'Her composure during introductions impressed the whole room.', example_ko_2 = '소개 중의 그녀의 침착함이 방 전체를 감동시켰어요.', example_en_3 = 'He maintained composure even when he forgot someone''s name.', example_ko_3 = '누군가의 이름을 잊어버렸을 때도 그는 침착함을 유지했어요.', example_en_4 = 'Composure in social settings reflects emotional maturity.', example_ko_4 = '사교적인 자리에서의 침착함은 감성적 성숙을 반영해요.', example_en_5 = 'She kept her composure and greeted everyone professionally.', example_ko_5 = '그녀는 침착함을 유지하며 모두에게 전문적으로 인사했어요.' WHERE id = 'w_greeting_B2_12';
UPDATE words SET example_en_2 = 'She followed the protocol for introducing senior officials.', example_ko_2 = '그녀는 고위 공직자 소개를 위한 의전을 따랐어요.', example_en_3 = 'The protocol for greeting the ambassador was explained in advance.', example_ko_3 = '대사에게 인사하는 의전은 사전에 설명됐어요.', example_en_4 = 'Understanding protocol is essential in diplomatic settings.', example_ko_4 = '외교적인 자리에서는 의전을 이해하는 것이 필수예요.', example_en_5 = 'He briefed the team on the greeting protocol before the event.', example_ko_5 = '그는 행사 전에 팀에게 인사 의전을 설명했어요.' WHERE id = 'w_greeting_B2_13';
UPDATE words SET example_en_2 = 'She reciprocated his bow with a polite one of her own.', example_ko_2 = '그녀는 그의 절에 자신도 정중하게 절로 화답했어요.', example_en_3 = 'He reciprocated the warm greeting with an equally warm one.', example_ko_3 = '그는 따뜻한 인사에 똑같이 따뜻하게 화답했어요.', example_en_4 = 'In social settings, it is natural to reciprocate kindness.', example_ko_4 = '사교적인 자리에서 친절에 화답하는 것은 자연스러운 일이에요.', example_en_5 = 'She smiled and reciprocated, making the moment feel genuine.', example_ko_5 = '그녀는 미소를 지으며 화답해서 그 순간이 진심으로 느껴지게 했어요.' WHERE id = 'w_greeting_B2_14';
UPDATE words SET example_en_2 = 'She entered the networking event with great poise.', example_ko_2 = '그녀는 네트워킹 행사에 훌륭한 품위로 입장했어요.', example_en_3 = 'His poise during the introduction impressed everyone in the room.', example_ko_3 = '소개 중의 그의 품위가 방 안의 모두를 감동시켰어요.', example_en_4 = 'Poise and confidence make every greeting memorable.', example_ko_4 = '품위와 자신감은 모든 인사를 기억에 남게 해요.', example_en_5 = 'She was admired for her poise in every social situation.', example_ko_5 = '그녀는 모든 사교적 상황에서 품위로 존경을 받았어요.' WHERE id = 'w_greeting_B2_15';
UPDATE words SET example_en_2 = 'She cultivated strong professional relationships over the years.', example_ko_2 = '그녀는 수년에 걸쳐 강한 직업적 관계를 쌓았어요.', example_en_3 = 'He used every greeting as a chance to cultivate a connection.', example_ko_3 = '그는 모든 인사를 인연을 쌓는 기회로 사용했어요.', example_en_4 = 'It takes time and effort to cultivate meaningful friendships.', example_ko_4 = '의미 있는 우정을 쌓는 데는 시간과 노력이 필요해요.', example_en_5 = 'Warm greetings are the first step to cultivating lasting bonds.', example_ko_5 = '따뜻한 인사는 오래가는 유대를 쌓는 첫 걸음이에요.' WHERE id = 'w_greeting_B2_16';
UPDATE words SET example_en_2 = 'A brief and sincere greeting is always better than a long one.', example_ko_2 = '간결하고 진심 어린 인사가 긴 인사보다 항상 더 좋아요.', example_en_3 = 'She valued brevity in conversation but never at the cost of warmth.', example_ko_3 = '그녀는 대화에서 간결함을 중요시했지만 따뜻함을 희생하지는 않았어요.', example_en_4 = 'A short but meaningful introduction showed his brevity.', example_ko_4 = '짧지만 의미 있는 소개가 그의 간결함을 보여줬어요.', example_en_5 = 'The art of a good greeting lies in its brevity and sincerity.', example_ko_5 = '좋은 인사의 예술은 간결함과 진심에 있어요.' WHERE id = 'w_greeting_B2_17';
UPDATE words SET example_en_2 = 'She greeted guests with a sense of distinction.', example_ko_2 = '그녀는 품격 있게 손님들을 맞이했어요.', example_en_3 = 'His introduction was noted for its clarity and distinction.', example_ko_3 = '그의 소개는 명확함과 품격으로 주목을 받았어요.', example_en_4 = 'Greeting with distinction sets you apart in social settings.', example_ko_4 = '품격 있는 인사는 사교적인 자리에서 당신을 돋보이게 해요.', example_en_5 = 'She carried herself with distinction in every interaction.', example_ko_5 = '그녀는 모든 상호 작용에서 품격 있는 자세를 유지했어요.' WHERE id = 'w_greeting_B2_18';
UPDATE words SET example_en_2 = 'He acknowledged the guests as they entered the hall.', example_ko_2 = '그는 손님들이 홀에 들어올 때 알아봤어요.', example_en_3 = 'She acknowledged his greeting with a warm smile.', example_ko_3 = '그녀는 따뜻한 미소로 그의 인사를 알아봤어요.', example_en_4 = 'It is important to acknowledge people when they join a group.', example_ko_4 = '그룹에 합류했을 때 사람들을 알아봐 주는 것이 중요해요.', example_en_5 = 'He acknowledged every newcomer with a handshake and a smile.', example_ko_5 = '그는 모든 신입을 악수와 미소로 알아봐 줬어요.' WHERE id = 'w_greeting_B2_19';
UPDATE words SET example_en_2 = 'His personable manner made him popular at social events.', example_ko_2 = '그의 붙임성 있는 태도 덕분에 사교 행사에서 인기가 많았어요.', example_en_3 = 'Being personable is a great asset in any first meeting.', example_ko_3 = '붙임성 있는 것은 어떤 첫 만남에서도 큰 자산이에요.', example_en_4 = 'She was described as personable and easy to get along with.', example_ko_4 = '그녀는 붙임성 있고 함께하기 쉬운 사람으로 묘사됐어요.', example_en_5 = 'A personable greeting leaves a lasting positive impression.', example_ko_5 = '붙임성 있는 인사는 오래도록 긍정적인 인상을 남겨요.' WHERE id = 'w_greeting_B2_20';
UPDATE words SET example_en_2 = 'A warm smile can convey welcome without a single word.', example_ko_2 = '따뜻한 미소 하나로 말 한마디 없이도 환영을 전달할 수 있어요.', example_en_3 = 'She conveys sincerity through her tone and body language.', example_ko_3 = '그녀는 어조와 몸짓으로 진심을 전달해요.', example_en_4 = 'He conveyed his gratitude with a heartfelt handshake.', example_ko_4 = '그는 진심 어린 악수로 감사를 전달했어요.', example_en_5 = 'A good greeting conveys respect and genuine interest.', example_ko_5 = '좋은 인사는 존중과 진심 어린 관심을 전달해요.' WHERE id = 'w_greeting_B2_21';
UPDATE words SET example_en_2 = 'The event had a degree of formality that required formal introductions.', example_ko_2 = '그 행사에는 공식적인 소개가 필요한 정도의 격식이 있었어요.', example_en_3 = 'She noticed that the meeting lacked the usual formality.', example_ko_3 = '그녀는 회의에 평소의 격식이 부족하다는 것을 알아차렸어요.', example_en_4 = 'Korean greetings often involve a level of formality and respect.', example_ko_4 = '한국의 인사에는 종종 어느 정도의 격식과 존중이 담겨 있어요.', example_en_5 = 'Dropping formality too soon can come across as disrespectful.', example_ko_5 = '너무 빨리 격식을 내려놓으면 무례하게 비칠 수 있어요.' WHERE id = 'w_greeting_B2_22';
UPDATE words SET example_en_2 = 'Her engaging personality made her memorable to everyone she met.', example_ko_2 = '그녀의 매력적인 성격 덕분에 만나는 모든 사람에게 기억에 남았어요.', example_en_3 = 'He gave an engaging self-introduction that drew laughter.', example_ko_3 = '그는 웃음을 자아내는 매력적인 자기소개를 했어요.', example_en_4 = 'An engaging greeting draws people in rather than pushing them away.', example_ko_4 = '매력적인 인사는 사람들을 밀어내는 것이 아니라 끌어당겨요.', example_en_5 = 'She found his engaging manner refreshing.', example_ko_5 = '그녀는 그의 매력적인 태도가 신선하게 느껴졌어요.' WHERE id = 'w_greeting_B2_23';
UPDATE words SET example_en_2 = 'Cross-cultural training helps demystify unfamiliar greeting norms.', example_ko_2 = '문화 간 훈련은 낯선 인사 규범을 쉽게 이해할 수 있게 해줘요.', example_en_3 = 'She worked to demystify the formalities for the newcomers.', example_ko_3 = '그녀는 신입들을 위해 격식을 쉽게 설명하려 했어요.', example_en_4 = 'He used simple examples to demystify Korean greeting culture.', example_ko_4 = '그는 간단한 예시로 한국 인사 문화를 쉽게 설명했어요.', example_en_5 = 'A good guide can demystify any cultural greeting practice.', example_ko_5 = '좋은 안내자는 어떤 문화적 인사 관행이든 쉽게 설명할 수 있어요.' WHERE id = 'w_greeting_B2_24';
UPDATE words SET example_en_2 = 'She picked up on the nuances in his greeting style.', example_ko_2 = '그녀는 그의 인사 방식에서 뉘앙스를 포착했어요.', example_en_3 = 'Understanding cultural nuances helps you greet people appropriately.', example_ko_3 = '문화적 뉘앙스를 이해하면 적절하게 인사하는 데 도움이 돼요.', example_en_4 = 'There are subtle nuances between a formal and a casual bow.', example_ko_4 = '격식 있는 절과 격식 없는 절 사이에는 미묘한 뉘앙스 차이가 있어요.', example_en_5 = 'She was sensitive to the nuances of every social interaction.', example_ko_5 = '그녀는 모든 사교적 상호 작용의 뉘앙스에 민감했어요.' WHERE id = 'w_greeting_B2_25';
UPDATE words SET example_en_2 = 'His amiable greeting put the nervous guest at ease.', example_ko_2 = '그의 상냥한 인사 덕분에 긴장한 손님이 편안해졌어요.', example_en_3 = 'She is known for her amiable and open manner with new people.', example_ko_3 = '그녀는 새로운 사람들에게 상냥하고 개방적인 태도로 알려져 있어요.', example_en_4 = 'An amiable host makes every guest feel valued.', example_ko_4 = '상냥한 호스트는 모든 손님이 소중하게 느끼게 해요.', example_en_5 = 'His amiable personality made him a natural at networking.', example_ko_5 = '그의 상냥한 성격 덕분에 그는 네트워킹에 자연스러웠어요.' WHERE id = 'w_greeting_B2_26';
UPDATE words SET example_en_2 = 'She seemed reserved at first but opened up over coffee.', example_ko_2 = '그녀는 처음에는 내성적으로 보였지만 커피를 마시며 마음을 열었어요.', example_en_3 = 'He is more reserved in formal settings than casual ones.', example_ko_3 = '그는 격식 없는 자리보다 격식 있는 자리에서 더 내성적이에요.', example_en_4 = 'Don''t misinterpret reserved behavior as unfriendliness.', example_ko_4 = '내성적인 행동을 불친절함으로 오해하지 마세요.', example_en_5 = 'She was reserved in introductions but warm once comfortable.', example_ko_5 = '그녀는 소개할 때는 내성적이었지만 편안해지면 따뜻해졌어요.' WHERE id = 'w_greeting_B2_27';
UPDATE words SET example_en_2 = 'She took the initiative to greet the CEO first.', example_ko_2 = '그녀는 솔선하여 CEO에게 먼저 인사했어요.', example_en_3 = 'Taking initiative in introductions shows confidence.', example_ko_3 = '소개에서 솔선하는 것은 자신감을 보여줘요.', example_en_4 = 'He showed initiative by welcoming the new members personally.', example_ko_4 = '그는 새 멤버들에게 직접 인사함으로써 솔선함을 보였어요.', example_en_5 = 'She appreciated his initiative in breaking the ice.', example_ko_5 = '그녀는 그가 솔선하여 분위기를 풀어준 것에 감사했어요.' WHERE id = 'w_greeting_B2_28';
UPDATE words SET example_en_2 = 'She was forthcoming about her role and responsibilities.', example_ko_2 = '그녀는 자신의 역할과 책임에 대해 기꺼이 이야기했어요.', example_en_3 = 'He was forthcoming with his contact details at the end.', example_ko_3 = '그는 마지막에 연락처를 기꺼이 공유했어요.', example_en_4 = 'Being forthcoming helps build trust in new relationships.', example_ko_4 = '기꺼이 이야기하는 자세는 새로운 관계에서 신뢰를 쌓는 데 도움이 돼요.', example_en_5 = 'She found him forthcoming and easy to talk to.', example_ko_5 = '그녀는 그가 기꺼이 이야기하고 대화하기 편한 사람이라고 느꼈어요.' WHERE id = 'w_greeting_B2_29';
UPDATE words SET example_en_2 = 'The convivial dinner made everyone feel at ease with each other.', example_ko_2 = '유쾌한 저녁 식사 덕분에 모두가 서로 편안해졌어요.', example_en_3 = 'A convivial atmosphere encourages people to introduce themselves.', example_ko_3 = '유쾌한 분위기는 사람들이 자기소개를 하도록 격려해요.', example_en_4 = 'He was known for creating a convivial mood wherever he went.', example_ko_4 = '그는 어디를 가든 유쾌한 분위기를 만드는 것으로 알려져 있었어요.', example_en_5 = 'She loved convivial gatherings where strangers became friends.', example_ko_5 = '그녀는 낯선 사람들이 친구가 되는 유쾌한 모임을 좋아했어요.' WHERE id = 'w_greeting_B2_30';
UPDATE words SET example_en_2 = 'An inclusive greeting makes sure no one feels left out.', example_ko_2 = '포용적인 인사는 아무도 소외되지 않도록 해요.', example_en_3 = 'She made a point of being inclusive when welcoming guests.', example_ko_3 = '그녀는 손님을 맞이할 때 포용적이려고 노력했어요.', example_en_4 = 'Inclusive language in greetings shows respect for diversity.', example_ko_4 = '인사에서의 포용적인 언어는 다양성에 대한 존중을 보여줘요.', example_en_5 = 'He made the event inclusive by welcoming everyone by name.', example_ko_5 = '그는 모두를 이름으로 불러 행사를 포용적으로 만들었어요.' WHERE id = 'w_greeting_B2_31';
UPDATE words SET example_en_2 = 'Her confident demeanor made the introduction feel effortless.', example_ko_2 = '그녀의 자신감 있는 태도 덕분에 소개가 수월하게 느껴졌어요.', example_en_3 = 'He maintained a calm demeanor even in a room full of strangers.', example_ko_3 = '낯선 사람들로 가득한 방에서도 그는 차분한 태도를 유지했어요.', example_en_4 = 'A professional demeanor is important in formal introductions.', example_ko_4 = '공식적인 소개에서 전문적인 태도가 중요해요.', example_en_5 = 'Positive demeanor is contagious — it makes others feel good too.', example_ko_5 = '긍정적인 태도는 전염성이 있어요. 다른 사람들도 기분 좋게 만들어요.' WHERE id = 'w_greeting_B2_32';
UPDATE words SET example_en_2 = 'Her captivating introduction made everyone want to know more.', example_ko_2 = '그녀의 매혹적인 소개 덕분에 모두가 더 알고 싶어했어요.', example_en_3 = 'He had a captivating way of making every person feel special.', example_ko_3 = '그는 모든 사람이 특별하게 느끼게 만드는 매혹적인 방식이 있었어요.', example_en_4 = 'Her captivating smile was the first thing people noticed.', example_ko_4 = '그녀의 매혹적인 미소는 사람들이 처음 알아채는 것이었어요.', example_en_5 = 'A captivating introduction is hard to forget.', example_ko_5 = '매혹적인 소개는 잊기 어려워요.' WHERE id = 'w_greeting_B2_33';
UPDATE words SET example_en_2 = 'Her greeting style became the benchmark for the entire department.', example_ko_2 = '그녀의 인사 방식은 부서 전체의 기준이 됐어요.', example_en_3 = 'He set a new benchmark for professionalism in first meetings.', example_ko_3 = '그는 첫 만남에서 전문성의 새로운 기준을 세웠어요.', example_en_4 = 'The host''s warmth was the benchmark for all event staff.', example_ko_4 = '호스트의 따뜻함이 모든 행사 직원들의 기준이 됐어요.', example_en_5 = 'A great first impression sets the benchmark for every meeting after.', example_ko_5 = '좋은 첫인상은 이후 모든 만남의 기준을 설정해요.' WHERE id = 'w_greeting_B2_34';
UPDATE words SET example_en_2 = 'A warm greeting helps establish rapport from the very start.', example_ko_2 = '따뜻한 인사는 처음부터 유대감을 확립하는 데 도움이 돼요.', example_en_3 = 'She worked hard to establish a positive first impression.', example_ko_3 = '그녀는 긍정적인 첫인상을 확립하기 위해 열심히 노력했어요.', example_en_4 = 'First meetings are a chance to establish trust.', example_ko_4 = '첫 만남은 신뢰를 확립할 기회예요.', example_en_5 = 'He greeted everyone personally to establish a friendly environment.', example_ko_5 = '그는 친근한 환경을 확립하기 위해 모두에게 직접 인사했어요.' WHERE id = 'w_greeting_B2_35';

