UPDATE words SET example_en_2 = 'His eloquent opening remarks set a powerful tone for the event.', example_ko_2 = '그의 웅변적인 개회사가 행사에 강력한 분위기를 만들었어요.', example_en_3 = 'She introduced herself in an eloquent and memorable way.', example_ko_3 = '그녀는 웅변적이고 기억에 남는 방식으로 자기소개를 했어요.', example_en_4 = 'An eloquent greeting leaves a powerful first impression.', example_ko_4 = '웅변적인 인사는 강력한 첫인상을 남겨요.', example_en_5 = 'He delivered an eloquent welcome speech to the delegates.', example_ko_5 = '그는 대표단에게 웅변적인 환영사를 전했어요.' WHERE id = 'w_greeting_C1_01';
UPDATE words SET example_en_2 = 'The distinguished professor was welcomed with great ceremony.', example_ko_2 = '저명한 교수님은 성대한 예식으로 환영받았어요.', example_en_3 = 'She is a distinguished figure in the world of diplomacy.', example_ko_3 = '그녀는 외교 세계에서 저명한 인물이에요.', example_en_4 = 'Being introduced to such a distinguished guest was an honor.', example_ko_4 = '그러한 저명한 손님께 소개받는 것은 영광이었어요.', example_en_5 = 'Distinguished guests deserve a greeting that reflects their status.', example_ko_5 = '저명한 손님들은 그들의 지위를 반영하는 인사를 받을 자격이 있어요.' WHERE id = 'w_greeting_C1_02';
UPDATE words SET example_en_2 = 'She stood poised and greeted each guest by name.', example_ko_2 = '그녀는 품위 있게 서서 각 손님을 이름으로 맞이했어요.', example_en_3 = 'He appeared poised and confident throughout the introductions.', example_ko_3 = '그는 소개 내내 침착하고 자신감 있게 보였어요.', example_en_4 = 'A poised greeting reflects years of social experience.', example_ko_4 = '품위 있는 인사는 수년간의 사교적 경험을 반영해요.', example_en_5 = 'She remained poised even when she forgot someone''s title.', example_ko_5 = '누군가의 직함을 잊어버렸을 때도 그녀는 침착함을 유지했어요.' WHERE id = 'w_greeting_C1_03';
UPDATE words SET example_en_2 = 'His affable manner won over the most reserved guests.', example_ko_2 = '그의 상냥한 태도는 가장 내성적인 손님들까지 사로잡았어요.', example_en_3 = 'She found him affable and easy to talk to right away.', example_ko_3 = '그녀는 그가 상냥하고 바로 대화하기 편한 사람이라고 느꼈어요.', example_en_4 = 'An affable host creates a welcoming environment for all.', example_ko_4 = '상냥한 호스트는 모두에게 환영하는 환경을 만들어요.', example_en_5 = 'His affable personality made him the heart of every gathering.', example_ko_5 = '그의 상냥한 성격 덕분에 그는 모든 모임의 중심이었어요.' WHERE id = 'w_greeting_C1_04';
UPDATE words SET example_en_2 = 'Her gregarious nature meant she never stood alone at parties.', example_ko_2 = '그녀의 사교적인 성격 덕분에 그녀는 파티에서 혼자 있는 법이 없었어요.', example_en_3 = 'A gregarious person finds networking effortless and enjoyable.', example_ko_3 = '사교적인 사람은 네트워킹을 수월하고 즐겁게 해요.', example_en_4 = 'He was the most gregarious person at every conference.', example_ko_4 = '그는 모든 컨퍼런스에서 가장 사교적인 사람이었어요.', example_en_5 = 'His gregarious spirit made first introductions feel natural.', example_ko_5 = '그의 사교적인 기질 덕분에 처음 소개가 자연스럽게 느껴졌어요.' WHERE id = 'w_greeting_C1_05';
UPDATE words SET example_en_2 = 'Her personable warmth made guests feel immediately at home.', example_ko_2 = '그녀의 호감 가는 따뜻함 덕분에 손님들이 즉시 편안해졌어요.', example_en_3 = 'He was personable and charming from the very first handshake.', example_ko_3 = '그는 첫 악수부터 호감 가고 매력적이었어요.', example_en_4 = 'A personable speaker draws the audience in immediately.', example_ko_4 = '호감 가는 연사는 청중을 즉시 끌어당겨요.', example_en_5 = 'She is described as both intelligent and personable.', example_ko_5 = '그녀는 지적이면서도 호감 가는 사람으로 묘사돼요.' WHERE id = 'w_greeting_C1_06';
UPDATE words SET example_en_2 = 'He was deferential to the senior diplomat throughout the meeting.', example_ko_2 = '그는 회의 내내 선임 외교관에게 공손했어요.', example_en_3 = 'A deferential bow shows respect in Korean professional culture.', example_ko_3 = '공손한 절은 한국 직업 문화에서 존중을 나타내요.', example_en_4 = 'She was deferential without being submissive.', example_ko_4 = '그녀는 복종하지 않으면서도 공손했어요.', example_en_5 = 'Being deferential to elders is deeply valued in Korean culture.', example_ko_5 = '어른에게 공손하게 대하는 것은 한국 문화에서 깊이 소중히 여겨져요.' WHERE id = 'w_greeting_C1_07';
UPDATE words SET example_en_2 = 'Her amiable approach diffused tension at the difficult meeting.', example_ko_2 = '그녀의 친절한 접근 덕분에 어려운 회의에서 긴장이 풀렸어요.', example_en_3 = 'He was amiable in all his dealings with the visiting delegates.', example_ko_3 = '그는 방문한 대표단 모두와의 교류에서 친절했어요.', example_en_4 = 'An amiable smile is the universal language of welcome.', example_ko_4 = '친절한 미소는 환영의 보편적 언어예요.', example_en_5 = 'She cultivated an amiable reputation over her long career.', example_ko_5 = '그녀는 오랜 경력을 통해 친절한 평판을 쌓았어요.' WHERE id = 'w_greeting_C1_08';
UPDATE words SET example_en_2 = 'The two leaders exchanged cordial greetings before the talks.', example_ko_2 = '두 지도자는 회담 전에 다정한 인사를 나눴어요.', example_en_3 = 'Despite their differences, they maintained a cordial relationship.', example_ko_3 = '의견 차이에도 불구하고 그들은 다정한 관계를 유지했어요.', example_en_4 = 'A cordial tone sets the stage for productive discussions.', example_ko_4 = '다정한 어조는 생산적인 논의의 무대를 설정해요.', example_en_5 = 'She invited him for a cordial catch-up over lunch.', example_ko_5 = '그녀는 그를 점심에 다정하게 근황 나누는 자리에 초대했어요.' WHERE id = 'w_greeting_C1_09';
UPDATE words SET example_en_2 = 'He greeted the board with a suave confidence that impressed everyone.', example_ko_2 = '그는 이사회를 세련된 자신감으로 맞이하여 모두를 감동시켰어요.', example_en_3 = 'A suave introduction can open doors in high-level circles.', example_ko_3 = '세련된 소개는 고위급 사교계에서 문을 열어줄 수 있어요.', example_en_4 = 'She found his suave manner both impressive and charming.', example_ko_4 = '그녀는 그의 세련된 태도가 인상적이면서도 매력적이라고 느꼈어요.', example_en_5 = 'His suave style made every introduction feel polished.', example_ko_5 = '그의 세련된 스타일은 모든 소개를 품위 있게 만들었어요.' WHERE id = 'w_greeting_C1_10';
UPDATE words SET example_en_2 = 'Her eloquence in the opening remarks won the audience over immediately.', example_ko_2 = '개회사에서 그녀의 웅변이 청중을 즉시 사로잡았어요.', example_en_3 = 'He was admired for his eloquence in diplomatic introductions.', example_ko_3 = '그는 외교적 소개에서의 웅변으로 존경을 받았어요.', example_en_4 = 'True eloquence lies in sincerity, not just vocabulary.', example_ko_4 = '진정한 웅변은 어휘가 아니라 진심에 있어요.', example_en_5 = 'Her eloquence made even a brief greeting feel memorable.', example_ko_5 = '그녀의 웅변 덕분에 짧은 인사조차 기억에 남았어요.' WHERE id = 'w_greeting_C1_11';
UPDATE words SET example_en_2 = 'Diplomacy in introductions means knowing what not to say.', example_ko_2 = '소개에서의 외교술은 무엇을 말하지 말아야 하는지 아는 것을 의미해요.', example_en_3 = 'She used diplomacy to smooth over the awkward introduction.', example_ko_3 = '그녀는 외교술을 사용해 어색한 소개를 부드럽게 처리했어요.', example_en_4 = 'He approached every social interaction with quiet diplomacy.', example_ko_4 = '그는 모든 사교적 상호 작용을 조용한 외교술로 임했어요.', example_en_5 = 'Diplomacy and warmth are the twin pillars of great greetings.', example_ko_5 = '외교술과 따뜻함은 훌륭한 인사의 두 기둥이에요.' WHERE id = 'w_greeting_C1_12';
UPDATE words SET example_en_2 = 'Being introduced by a person of prestige elevates your own standing.', example_ko_2 = '명성 있는 사람에게 소개받는 것은 자신의 위상을 높여줘요.', example_en_3 = 'He greeted the dignitary with due recognition of her prestige.', example_ko_3 = '그는 그녀의 명성에 합당한 인정으로 고위 인사에게 인사했어요.', example_en_4 = 'The prestige of the occasion called for a formal greeting.', example_ko_4 = '그 자리의 위신에 걸맞게 격식 있는 인사가 필요했어요.', example_en_5 = 'She earned prestige through years of respectful and warm interactions.', example_ko_5 = '그녀는 수년간의 존중하고 따뜻한 교류를 통해 명성을 얻었어요.' WHERE id = 'w_greeting_C1_13';
UPDATE words SET example_en_2 = 'Her cultivated poise was evident from the moment she entered.', example_ko_2 = '그녀가 들어서는 순간부터 교양 있는 품위가 느껴졌어요.', example_en_3 = 'He greeted the foreign delegation with cultivated diplomacy.', example_ko_3 = '그는 교양 있는 외교술로 외국 대표단을 맞이했어요.', example_en_4 = 'A cultivated greeting reflects education and social awareness.', example_ko_4 = '교양 있는 인사는 교육과 사회적 인식을 반영해요.', example_en_5 = 'She was praised for her cultivated and gracious manner.', example_ko_5 = '그녀는 교양 있고 우아한 태도로 칭찬을 받았어요.' WHERE id = 'w_greeting_C1_14';
UPDATE words SET example_en_2 = 'She looked composed and approachable as guests arrived.', example_ko_2 = '손님들이 도착하는 동안 그녀는 차분하고 다가가기 쉬운 모습이었어요.', example_en_3 = 'He was composed even when introduced to the head of state.', example_ko_3 = '국가 원수에게 소개받을 때도 그는 차분했어요.', example_en_4 = 'Staying composed during introductions signals emotional strength.', example_ko_4 = '소개 중에 차분함을 유지하는 것은 감성적 강인함을 나타내요.', example_en_5 = 'She always appeared composed, no matter the occasion.', example_ko_5 = '그녀는 어떤 자리에서도 항상 차분해 보였어요.' WHERE id = 'w_greeting_C1_15';
UPDATE words SET example_en_2 = 'A warm tone can facilitate even the most awkward of introductions.', example_ko_2 = '따뜻한 어조는 가장 어색한 소개조차 수월하게 해줄 수 있어요.', example_en_3 = 'She used humor to facilitate the networking session.', example_ko_3 = '그녀는 유머를 이용해 네트워킹 세션을 수월하게 했어요.', example_en_4 = 'Good hosting skills facilitate connections between guests.', example_ko_4 = '좋은 호스팅 능력은 손님들 사이의 연결을 수월하게 해요.', example_en_5 = 'He used name tags to facilitate introductions at the event.', example_ko_5 = '그는 행사에서 소개를 수월하게 하기 위해 명찰을 사용했어요.' WHERE id = 'w_greeting_C1_16';
UPDATE words SET example_en_2 = 'His calm demeanour put the interviewer at ease immediately.', example_ko_2 = '그의 차분한 행동거지 덕분에 면접관이 즉시 편안해졌어요.', example_en_3 = 'She maintained a professional demeanour throughout the ceremony.', example_ko_3 = '그녀는 행사 내내 전문적인 행동거지를 유지했어요.', example_en_4 = 'A steady demeanour in formal settings inspires confidence.', example_ko_4 = '격식 있는 자리에서의 안정된 행동거지는 신뢰를 심어줘요.', example_en_5 = 'His warm demeanour made strangers feel like old friends.', example_ko_5 = '그의 따뜻한 행동거지 덕분에 낯선 사람들이 오래된 친구처럼 느껴졌어요.' WHERE id = 'w_greeting_C1_17';
UPDATE words SET example_en_2 = 'In Korean tradition, elders are venerated with a deep bow.', example_ko_2 = '한국 전통에서 어른은 깊은 절로 공경해요.', example_en_3 = 'The venerable teacher was greeted with great respect.', example_ko_3 = '존경받는 선생님은 깊은 존중으로 인사를 받았어요.', example_en_4 = 'He taught his students to venerate those who came before them.', example_ko_4 = '그는 학생들에게 앞서 온 사람들을 공경하도록 가르쳤어요.', example_en_5 = 'To venerate someone is to greet them with the highest respect.', example_ko_5 = '누군가를 공경한다는 것은 최고의 존중으로 인사하는 것이에요.' WHERE id = 'w_greeting_C1_18';
UPDATE words SET example_en_2 = 'He was careful not to ingratiate himself in a way that felt insincere.', example_ko_2 = '그는 진심이 없어 보이는 방식으로 환심을 사지 않으려 조심했어요.', example_en_3 = 'She tried to ingratiate herself without compromising her integrity.', example_ko_3 = '그녀는 진실성을 지키면서 환심을 사려고 했어요.', example_en_4 = 'There is a fine line between being charming and trying to ingratiate.', example_ko_4 = '매력적이게 행동하는 것과 환심을 사려는 것 사이에는 얇은 경계가 있어요.', example_en_5 = 'Authentic warmth is very different from trying to ingratiate oneself.', example_ko_5 = '진정한 따뜻함은 환심을 사려는 것과 매우 달라요.' WHERE id = 'w_greeting_C1_19';
UPDATE words SET example_en_2 = 'She was magnanimous in acknowledging her competitor''s success.', example_ko_2 = '그녀는 경쟁자의 성공을 인정하는 데 관대했어요.', example_en_3 = 'A magnanimous greeting after a conflict restores goodwill.', example_ko_3 = '충돌 후의 관대한 인사는 호감을 회복해요.', example_en_4 = 'He showed a magnanimous spirit by welcoming his critics warmly.', example_ko_4 = '그는 비평가들을 따뜻하게 환영함으로써 관대한 정신을 보였어요.', example_en_5 = 'Being magnanimous in social situations earns respect and admiration.', example_ko_5 = '사교적인 상황에서 관대하게 행동하면 존경과 감탄을 얻어요.' WHERE id = 'w_greeting_C1_20';
UPDATE words SET example_en_2 = 'Her effusive praise made the newcomer feel truly special.', example_ko_2 = '그녀의 넘치는 칭찬 덕분에 신입이 정말 특별하게 느꼈어요.', example_en_3 = 'He was known for his effusive greetings at every occasion.', example_ko_3 = '그는 모든 자리에서 넘치는 인사로 알려져 있었어요.', example_en_4 = 'While effusive, she was always genuine in her warmth.', example_ko_4 = '넘치게 표현하면서도 그녀의 따뜻함은 항상 진심이었어요.', example_en_5 = 'An effusive welcome can make any event feel festive.', example_ko_5 = '넘치는 환영은 어떤 행사든 축제처럼 느끼게 해줄 수 있어요.' WHERE id = 'w_greeting_C1_21';
UPDATE words SET example_en_2 = 'His unassuming greeting was far more effective than a grand one.', example_ko_2 = '그의 겸손한 인사는 화려한 것보다 훨씬 더 효과적이었어요.', example_en_3 = 'She was unassuming but deeply impressive to everyone she met.', example_ko_3 = '그녀는 겸손했지만 만나는 모든 사람에게 깊은 인상을 남겼어요.', example_en_4 = 'An unassuming manner shows true confidence and security.', example_ko_4 = '겸손한 태도는 진정한 자신감과 여유를 보여줘요.', example_en_5 = 'His unassuming charm won people over without any effort.', example_ko_5 = '그의 겸손한 매력은 아무 노력 없이도 사람들을 사로잡았어요.' WHERE id = 'w_greeting_C1_22';
UPDATE words SET example_en_2 = 'She built rapport with everyone she met at the summit.', example_ko_2 = '그녀는 정상회담에서 만난 모든 사람과 신뢰 관계를 쌓았어요.', example_en_3 = 'Good rapport starts with a genuine and attentive greeting.', example_ko_3 = '좋은 신뢰 관계는 진심 어린 주의 깊은 인사에서 시작돼요.', example_en_4 = 'He had a natural talent for building rapport with strangers.', example_ko_4 = '그는 낯선 사람과 신뢰 관계를 쌓는 천부적인 재능이 있었어요.', example_en_5 = 'Rapport built in the first minutes of a meeting can last years.', example_ko_5 = '만남의 처음 몇 분에서 쌓은 신뢰 관계는 수년간 지속될 수 있어요.' WHERE id = 'w_greeting_C1_23';
UPDATE words SET example_en_2 = 'People are predisposed to trust those who greet them with eye contact.', example_ko_2 = '사람들은 눈을 맞추며 인사하는 사람을 신뢰하는 경향이 있어요.', example_en_3 = 'She was predisposed to like anyone who greeted her warmly.', example_ko_3 = '그녀는 따뜻하게 인사하는 사람이면 누구든 좋아하는 경향이 있었어요.', example_en_4 = 'We are predisposed to respond positively to genuine friendliness.', example_ko_4 = '우리는 진정한 친근함에 긍정적으로 반응하는 경향이 있어요.', example_en_5 = 'He was predisposed to making introductions feel effortless.', example_ko_5 = '그는 소개가 수월하게 느껴지도록 하는 경향이 있었어요.' WHERE id = 'w_greeting_C1_24';
UPDATE words SET example_en_2 = 'She greeted her counterpart with warmth despite the tense situation.', example_ko_2 = '그녀는 긴장된 상황에서도 상대방을 따뜻하게 맞이했어요.', example_en_3 = 'He introduced his counterpart from the partner company.', example_ko_3 = '그는 파트너 회사의 상대방을 소개했어요.', example_en_4 = 'Greeting your counterpart respectfully sets a positive tone.', example_ko_4 = '상대방을 존중하며 인사하면 긍정적인 분위기가 만들어져요.', example_en_5 = 'She and her foreign counterpart exchanged formal greetings.', example_ko_5 = '그녀와 외국 상대방은 격식 있는 인사를 나눴어요.' WHERE id = 'w_greeting_C1_25';
UPDATE words SET example_en_2 = 'His friendly overture led to a lasting business partnership.', example_ko_2 = '그의 친근한 첫 발걸음이 지속적인 비즈니스 파트너십으로 이어졌어요.', example_en_3 = 'She made an overture of friendship with a warm introduction.', example_ko_3 = '그녀는 따뜻한 소개로 우정의 첫 발걸음을 내딛었어요.', example_en_4 = 'A well-timed overture can transform a stranger into an ally.', example_ko_4 = '적절한 시기의 첫 발걸음은 낯선 사람을 동맹으로 만들 수 있어요.', example_en_5 = 'He accepted her overture and agreed to meet for coffee.', example_ko_5 = '그는 그녀의 제안을 받아들여 커피 약속에 동의했어요.' WHERE id = 'w_greeting_C1_26';
UPDATE words SET example_en_2 = 'The event demanded strict decorum from all attendees.', example_ko_2 = '그 행사는 모든 참석자에게 엄격한 예의범절을 요구했어요.', example_en_3 = 'She maintained decorum even when the conversation became heated.', example_ko_3 = '대화가 격해졌을 때도 그녀는 예의범절을 유지했어요.', example_en_4 = 'He briefed staff on decorum before the formal reception.', example_ko_4 = '그는 공식 환영 행사 전에 직원들에게 예의범절을 설명했어요.', example_en_5 = 'Proper decorum in greetings reflects your cultural awareness.', example_ko_5 = '인사에서의 적절한 예의범절은 문화적 인식을 반영해요.' WHERE id = 'w_greeting_C1_27';
UPDATE words SET example_en_2 = 'Observing propriety when greeting senior officials is essential.', example_ko_2 = '고위 공직자에게 인사할 때 적절함을 지키는 것은 필수예요.', example_en_3 = 'She always observed propriety, no matter the informality of the setting.', example_ko_3 = '그녀는 자리가 아무리 격식 없어도 항상 적절함을 지켰어요.', example_en_4 = 'A sense of propriety guides how we greet in different cultures.', example_ko_4 = '적절함에 대한 감각이 다양한 문화에서 인사하는 방식을 안내해요.', example_en_5 = 'His propriety in formal settings was noted and admired.', example_ko_5 = '격식 있는 자리에서 그의 적절함은 주목을 받고 감탄을 받았어요.' WHERE id = 'w_greeting_C1_28';
UPDATE words SET example_en_2 = 'Her disarming warmth broke the tension in the room.', example_ko_2 = '그녀의 긴장을 풀어주는 따뜻함이 방의 긴장을 깨트렸어요.', example_en_3 = 'He had a disarming way of making people feel immediately at ease.', example_ko_3 = '그는 사람들이 즉시 편안해지도록 하는 긴장을 풀어주는 방식이 있었어요.', example_en_4 = 'A disarming smile is more powerful than any formal greeting.', example_ko_4 = '긴장을 풀어주는 미소는 어떤 격식 있는 인사보다 강력해요.', example_en_5 = 'Her disarming honesty made people trust her from the first meeting.', example_ko_5 = '그녀의 긴장을 풀어주는 솔직함 덕분에 사람들은 첫 만남부터 그녀를 신뢰했어요.' WHERE id = 'w_greeting_C1_29';
UPDATE words SET example_en_2 = 'Cutting out verbiage from your greeting makes it more powerful.', example_ko_2 = '인사에서 장황한 말을 줄이면 더 강력해져요.', example_en_3 = 'She advised him to avoid verbiage when introducing himself.', example_ko_3 = '그녀는 자기소개를 할 때 장황한 말을 피하라고 조언했어요.', example_en_4 = 'The best greetings have no unnecessary verbiage.', example_ko_4 = '최고의 인사에는 불필요한 장황한 말이 없어요.', example_en_5 = 'His speech was noted for its absence of verbiage.', example_ko_5 = '그의 연설은 장황한 말이 없는 것으로 주목을 받았어요.' WHERE id = 'w_greeting_C1_30';
UPDATE words SET example_en_2 = 'The opulent venue set high expectations for the meeting.', example_ko_2 = '화려한 장소가 회의에 대한 기대를 높였어요.', example_en_3 = 'Guests were welcomed in an opulent hall lined with flowers.', example_ko_3 = '손님들은 꽃으로 장식된 화려한 홀에서 환영을 받았어요.', example_en_4 = 'The opulent setting called for an equally polished greeting.', example_ko_4 = '화려한 환경에는 그에 걸맞게 세련된 인사가 필요했어요.', example_en_5 = 'She was greeted in an opulent dining room by the host.', example_ko_5 = '그녀는 호스트에게 화려한 식당에서 환영을 받았어요.' WHERE id = 'w_greeting_C1_31';
UPDATE words SET example_en_2 = 'She had an inimitable way of welcoming strangers as friends.', example_ko_2 = '그녀는 낯선 사람들을 친구처럼 환영하는 독보적인 방식이 있었어요.', example_en_3 = 'His inimitable charm was evident from the very first hello.', example_ko_3 = '그의 독보적인 매력은 첫 안녕이라는 인사부터 뚜렷했어요.', example_en_4 = 'She has an inimitable style of putting people at ease.', example_ko_4 = '그녀는 사람들을 편안하게 하는 독보적인 스타일이 있어요.', example_en_5 = 'His inimitable personality made every first meeting memorable.', example_ko_5 = '그의 독보적인 성격 덕분에 모든 첫 만남이 기억에 남았어요.' WHERE id = 'w_greeting_C1_32';
UPDATE words SET example_en_2 = 'She was praised for the candor she showed in her introduction.', example_ko_2 = '그녀는 소개에서 보여준 솔직함으로 칭찬을 받았어요.', example_en_3 = 'His candor was refreshing — he said exactly what he meant.', example_ko_3 = '그의 솔직함은 신선했어요. 그는 생각한 것을 그대로 말했어요.', example_en_4 = 'Candor in a greeting builds trust faster than flattery.', example_ko_4 = '인사에서의 솔직함은 아첨보다 빠르게 신뢰를 쌓아요.', example_en_5 = 'She appreciated his candor and felt she could trust him.', example_ko_5 = '그녀는 그의 솔직함에 감사하며 그를 신뢰할 수 있다고 느꼈어요.' WHERE id = 'w_greeting_C1_33';
UPDATE words SET example_en_2 = 'The summit''s warm opening greeting signaled a new entente.', example_ko_2 = '정상회담의 따뜻한 개회 인사는 새로운 우호 관계를 알렸어요.', example_en_3 = 'Their entente began with a simple handshake and a smile.', example_ko_3 = '그들의 우호 관계는 간단한 악수와 미소로 시작됐어요.', example_en_4 = 'A cordial greeting can be the first step toward entente.', example_ko_4 = '다정한 인사는 우호 관계로 가는 첫 걸음이 될 수 있어요.', example_en_5 = 'The formal entente between the two groups began with a shared meal.', example_ko_5 = '두 그룹 사이의 공식 우호 관계는 함께하는 식사로 시작됐어요.' WHERE id = 'w_greeting_C1_34';
UPDATE words SET example_en_2 = 'A salutary introduction reminds us of the value of human connection.', example_ko_2 = '유익한 소개는 인간 연결의 가치를 상기시켜줘요.', example_en_3 = 'His salutary reminder to greet everyone equally was well received.', example_ko_3 = '모두에게 똑같이 인사하라는 그의 유익한 조언은 잘 받아들여졌어요.', example_en_4 = 'A salutary practice is to greet with a genuine compliment.', example_ko_4 = '진심 어린 칭찬으로 인사하는 것은 유익한 습관이에요.', example_en_5 = 'She found the workshop''s focus on salutary greetings very helpful.', example_ko_5 = '그녀는 워크샵의 유익한 인사에 대한 초점이 매우 도움이 됐어요.' WHERE id = 'w_greeting_C1_35';

