-- C2 (35단어)
-- ══════════════════════════════════════
UPDATE words SET example_en_2 = 'His urbane greeting set the tone for a sophisticated evening.', example_ko_2 = '그의 세련된 인사가 격조 있는 저녁의 분위기를 결정했어요.', example_en_3 = 'She was known for her urbane wit and gracious manner.', example_ko_3 = '그녀는 세련된 위트와 우아한 태도로 알려져 있었어요.', example_en_4 = 'An urbane host makes every guest feel effortlessly welcome.', example_ko_4 = '세련된 호스트는 모든 손님이 자연스럽게 환영받는다고 느끼게 해요.', example_en_5 = 'He greeted the dignitaries in a way that was urbane and refined.', example_ko_5 = '그는 세련되고 품위 있는 방식으로 고위 인사들에게 인사했어요.' WHERE id = 'w_greeting_C2_01';
UPDATE words SET example_en_2 = 'He greeted the crowd with a debonair bow and a smile.', example_ko_2 = '그는 우아한 절과 미소로 군중에게 인사했어요.', example_en_3 = 'Her debonair manner charmed everyone at the reception.', example_ko_3 = '그녀의 우아한 태도가 환영 행사의 모든 사람을 매혹시켰어요.', example_en_4 = 'A debonair style makes introductions feel effortless and natural.', example_ko_4 = '우아한 스타일은 소개를 수월하고 자연스럽게 느끼게 해요.', example_en_5 = 'He was described as debonair and unforgettable by all who met him.', example_ko_5 = '그는 만나는 모든 사람들에게 우아하고 잊을 수 없는 사람으로 묘사됐어요.' WHERE id = 'w_greeting_C2_02';
UPDATE words SET example_en_2 = 'Her refined manners were apparent from the first greeting.', example_ko_2 = '첫 인사부터 그녀의 품위 있는 태도가 분명했어요.', example_en_3 = 'He delivered a refined and thoughtful welcome address.', example_ko_3 = '그는 품위 있고 사려 깊은 환영사를 전했어요.', example_en_4 = 'A refined introduction shows preparation and respect.', example_ko_4 = '품위 있는 소개는 준비성과 존중을 보여줘요.', example_en_5 = 'She was admired for her refined and gracious social manner.', example_ko_5 = '그녀는 품위 있고 우아한 사교적 태도로 감탄을 받았어요.' WHERE id = 'w_greeting_C2_03';
UPDATE words SET example_en_2 = 'She was gracious to everyone, regardless of their status.', example_ko_2 = '그녀는 지위에 관계없이 모든 사람에게 우아하게 대했어요.', example_en_3 = 'He gave a gracious nod to each delegate as they entered.', example_ko_3 = '그는 대표단이 들어올 때마다 우아하게 고개를 끄덕였어요.', example_en_4 = 'A gracious host greets guests at the door personally.', example_ko_4 = '우아한 호스트는 문에서 손님을 직접 맞이해요.', example_en_5 = 'Her gracious farewell left a lasting positive impression.', example_ko_5 = '그녀의 우아한 작별 인사는 오래도록 긍정적인 인상을 남겼어요.' WHERE id = 'w_greeting_C2_04';
UPDATE words SET example_en_2 = 'The ceremonious welcome included a speech and formal introductions.', example_ko_2 = '의례적인 환영에는 연설과 공식 소개가 포함됐어요.', example_en_3 = 'He followed every ceremonious tradition of the formal dinner.', example_ko_3 = '그는 공식 만찬의 모든 의례적 전통을 따랐어요.', example_en_4 = 'The ceremonious greeting reflected the importance of the occasion.', example_ko_4 = '의례적인 인사는 그 자리의 중요성을 반영했어요.', example_en_5 = 'A ceremonious bow is expected in certain cultural contexts.', example_ko_5 = '특정 문화적 상황에서는 의례적인 절이 기대돼요.' WHERE id = 'w_greeting_C2_05';
UPDATE words SET example_en_2 = 'His magnanimous response to criticism earned him great respect.', example_ko_2 = '비판에 대한 그의 관대한 반응이 그에게 큰 존경을 안겨줬어요.', example_en_3 = 'She extended a magnanimous welcome to her longtime rival.', example_ko_3 = '그녀는 오랜 라이벌에게 관대한 환영을 건넸어요.', example_en_4 = 'A magnanimous greeting after a dispute is a sign of maturity.', example_ko_4 = '분쟁 후의 관대한 인사는 성숙함의 표시예요.', example_en_5 = 'He is known for his magnanimous spirit in all situations.', example_ko_5 = '그는 모든 상황에서 관대한 정신으로 알려져 있어요.' WHERE id = 'w_greeting_C2_06';
UPDATE words SET example_en_2 = 'The venerable founder was greeted with a standing ovation.', example_ko_2 = '존경받는 창립자는 기립 박수로 맞이받았어요.', example_en_3 = 'She is a venerable figure whose name alone commands respect.', example_ko_3 = '그녀는 이름만으로도 존경을 이끌어내는 존경받는 인물이에요.', example_en_4 = 'Greeting a venerable elder with a bow shows deep respect.', example_ko_4 = '존경받는 어른에게 절로 인사하는 것은 깊은 존중을 나타내요.', example_en_5 = 'He was treated as venerable by all who knew his work.', example_ko_5 = '그는 그의 작업을 아는 모든 사람들에게 존경받는 인물로 대우받았어요.' WHERE id = 'w_greeting_C2_07';
UPDATE words SET example_en_2 = 'State banquets require absolute decorum in all greetings.', example_ko_2 = '국가 만찬은 모든 인사에서 완벽한 예의범절을 요구해요.', example_en_3 = 'She observed decorum even in the most informal settings.', example_ko_3 = '그녀는 가장 격식 없는 자리에서도 예의범절을 지켰어요.', example_en_4 = 'Maintaining decorum during introductions signals good breeding.', example_ko_4 = '소개 중에 예의범절을 유지하는 것은 좋은 교양을 나타내요.', example_en_5 = 'The guests were reminded of the expected decorum before entering.', example_ko_5 = '손님들은 입장 전에 기대되는 예의범절을 상기시킴을 받았어요.' WHERE id = 'w_greeting_C2_08';
UPDATE words SET example_en_2 = 'Diplomatic protocol dictates how heads of state greet each other.', example_ko_2 = '외교 의전은 국가 원수들이 서로 인사하는 방식을 규정해요.', example_en_3 = 'She briefed the team on the greeting protocol before the visit.', example_ko_3 = '그녀는 방문 전에 팀에게 인사 의전을 설명했어요.', example_en_4 = 'Violating protocol in a greeting can cause diplomatic difficulties.', example_ko_4 = '인사에서 의전을 위반하면 외교적 어려움을 초래할 수 있어요.', example_en_5 = 'He followed every detail of the official protocol precisely.', example_ko_5 = '그는 공식 의전의 모든 세부 사항을 정확하게 따랐어요.' WHERE id = 'w_greeting_C2_09';
UPDATE words SET example_en_2 = 'The ambassador opened the summit with a formal greeting.', example_ko_2 = '대사는 공식 인사로 정상회담을 열었어요.', example_en_3 = 'She was introduced to the ambassador at the state reception.', example_ko_3 = '그녀는 국가 환영 행사에서 대사에게 소개받았어요.', example_en_4 = 'The ambassador greeted each delegation with measured warmth.', example_ko_4 = '대사는 각 대표단을 절제된 따뜻함으로 맞이했어요.', example_en_5 = 'Meeting the ambassador in person was a once-in-a-lifetime honor.', example_ko_5 = '대사를 직접 만나는 것은 일생에 한 번의 영광이었어요.' WHERE id = 'w_greeting_C2_10';
UPDATE words SET example_en_2 = 'The audience rose to felicitate the retiring dean.', example_ko_2 = '청중은 은퇴하는 학장을 축하하기 위해 자리에서 일어났어요.', example_en_3 = 'She was invited to felicitate the laureate at the ceremony.', example_ko_3 = '그녀는 행사에서 수상자를 축하하기 위해 초대됐어요.', example_en_4 = 'He took a moment to felicitate each new arrival personally.', example_ko_4 = '그는 새로 도착한 각 사람을 직접 축하하는 시간을 가졌어요.', example_en_5 = 'To felicitate someone with sincerity is the highest form of greeting.', example_ko_5 = '누군가를 진심으로 축하하는 것은 인사의 가장 높은 형태예요.' WHERE id = 'w_greeting_C2_11';
UPDATE words SET example_en_2 = 'The formal salutation at the start of the letter set a respectful tone.', example_ko_2 = '편지 시작의 격식 있는 인사말이 존중하는 분위기를 만들었어요.', example_en_3 = 'She used the correct salutation when addressing the chairperson.', example_ko_3 = '그녀는 의장에게 인사할 때 올바른 인사말을 사용했어요.', example_en_4 = 'A salutation in correspondence reflects your level of formality.', example_ko_4 = '서한에서의 인사말은 격식 수준을 반영해요.', example_en_5 = 'The salutation he chose conveyed both respect and warmth.', example_ko_5 = '그가 선택한 인사말은 존중과 따뜻함을 동시에 전달했어요.' WHERE id = 'w_greeting_C2_12';
UPDATE words SET example_en_2 = 'The courtiers performed obeisance before the visiting sovereign.', example_ko_2 = '신하들은 방문한 군주 앞에서 절을 올렸어요.', example_en_3 = 'She received their obeisance with quiet dignity.', example_ko_3 = '그녀는 조용한 품위로 그들의 절을 받았어요.', example_en_4 = 'Deep obeisance is still practiced in formal court ceremonies.', example_ko_4 = '깊은 절은 아직도 공식 궁정 행사에서 행해져요.', example_en_5 = 'He bowed in obeisance as the elder entered the room.', example_ko_5 = '어른이 방에 들어서자 그는 절로 공경을 표했어요.' WHERE id = 'w_greeting_C2_13';
UPDATE words SET example_en_2 = 'She was honored to speak at the graduation convocation.', example_ko_2 = '그녀는 졸업식에서 연설하는 영광을 얻었어요.', example_en_3 = 'The chancellor greeted each graduate at the convocation.', example_ko_3 = '총장은 졸업식에서 각 졸업생에게 인사했어요.', example_en_4 = 'The convocation opened with a formal welcome address.', example_ko_4 = '졸업식은 공식 환영사로 시작됐어요.', example_en_5 = 'He remembered his convocation as the most emotional greeting of his life.', example_ko_5 = '그는 졸업식을 자신의 삶에서 가장 감동적인 인사로 기억했어요.' WHERE id = 'w_greeting_C2_14';
UPDATE words SET example_en_2 = 'Her benevolence toward strangers made every event feel like a reunion.', example_ko_2 = '낯선 사람들에 대한 그녀의 선의 덕분에 모든 행사가 재회처럼 느껴졌어요.', example_en_3 = 'He greeted even his critics with benevolence and dignity.', example_ko_3 = '그는 비평가들에게도 선의와 품위로 인사했어요.', example_en_4 = 'True benevolence in greeting asks nothing in return.', example_ko_4 = '인사에서의 진정한 선의는 아무것도 바라지 않아요.', example_en_5 = 'Her benevolence was the quality people remembered most about her.', example_ko_5 = '그녀의 선의는 사람들이 그녀에 대해 가장 기억하는 자질이었어요.' WHERE id = 'w_greeting_C2_15';
UPDATE words SET example_en_2 = 'Her warm welcome earned the approbation of all senior staff.', example_ko_2 = '그녀의 따뜻한 환영이 모든 선임 직원의 칭찬을 받았어요.', example_en_3 = 'He sought approbation through kind and respectful greetings.', example_ko_3 = '그는 친절하고 존중하는 인사를 통해 칭찬을 구했어요.', example_en_4 = 'She was delighted to receive approbation from the committee.', example_ko_4 = '그녀는 위원회로부터 승인을 받아 기뻤어요.', example_en_5 = 'Social approbation often starts with how you greet people.', example_ko_5 = '사회적 칭찬은 종종 사람들에게 인사하는 방식에서 시작돼요.' WHERE id = 'w_greeting_C2_16';
UPDATE words SET example_en_2 = 'He greeted the newest intern without any trace of hauteur.', example_ko_2 = '그는 어떤 거만함도 없이 가장 최근 입사한 인턴에게 인사했어요.', example_en_3 = 'Her lack of hauteur made her accessible to everyone.', example_ko_3 = '거만함이 없는 그녀는 모든 사람에게 접근하기 쉬운 사람이었어요.', example_en_4 = 'Hauteur in a greeting is immediately off-putting.', example_ko_4 = '인사에서의 거만함은 즉시 거부감을 줘요.', example_en_5 = 'She was praised for her complete absence of hauteur.', example_ko_5 = '그녀는 거만함이 전혀 없는 것으로 칭찬을 받았어요.' WHERE id = 'w_greeting_C2_17';
UPDATE words SET example_en_2 = 'Her warm intercession helped two estranged colleagues reconnect.', example_ko_2 = '그녀의 따뜻한 중재 덕분에 두 소원해진 동료가 다시 연결됐어요.', example_en_3 = 'He used intercession to introduce the two rivals gracefully.', example_ko_3 = '그는 두 라이벌을 우아하게 소개하기 위해 중재를 사용했어요.', example_en_4 = 'Intercession in social settings can prevent misunderstandings.', example_ko_4 = '사교적인 자리에서의 중재는 오해를 방지할 수 있어요.', example_en_5 = 'She acted as intercession between the two groups at the summit.', example_ko_5 = '그녀는 정상회담에서 두 그룹 사이의 중재 역할을 했어요.' WHERE id = 'w_greeting_C2_18';
UPDATE words SET example_en_2 = 'She took to the stage with panache and addressed the audience.', example_ko_2 = '그녀는 기개 있게 무대에 올라 청중에게 인사했어요.', example_en_3 = 'He introduced himself with such panache that everyone applauded.', example_ko_3 = '그는 기개 있게 자기소개를 해서 모두가 박수를 쳤어요.', example_en_4 = 'Greeting a crowd with panache requires confidence and charm.', example_ko_4 = '기개 있게 군중에게 인사하려면 자신감과 매력이 필요해요.', example_en_5 = 'Her panache in every introduction made her unforgettable.', example_ko_5 = '모든 소개에서 그녀의 기개가 그녀를 잊을 수 없게 만들었어요.' WHERE id = 'w_greeting_C2_19';
UPDATE words SET example_en_2 = 'The ambassador greeted in accordance with the terms of suzerainty.', example_ko_2 = '대사는 종주권의 조건에 따라 인사했어요.', example_en_3 = 'Suzerainty implied a hierarchy that shaped the greeting protocol.', example_ko_3 = '종주권은 인사 의전을 형성하는 위계를 내포했어요.', example_en_4 = 'He navigated the suzerainty implied in the formal greeting order.', example_ko_4 = '그는 공식 인사 순서에 내포된 종주권을 능숙하게 다뤘어요.', example_en_5 = 'Under suzerainty, the receiving state shows deference in its greeting.', example_ko_5 = '종주권 하에서 수령국은 인사에서 복종을 보여요.' WHERE id = 'w_greeting_C2_20';
UPDATE words SET example_en_2 = 'Her gravitas meant her entrance silenced the room instantly.', example_ko_2 = '그녀의 무게감 덕분에 그녀가 입장하는 순간 방이 조용해졌어요.', example_en_3 = 'He carries gravitas in every handshake and word.', example_ko_3 = '그는 모든 악수와 말에 무게감을 담고 있어요.', example_en_4 = 'True gravitas cannot be faked — it is earned through experience.', example_ko_4 = '진정한 무게감은 꾸밀 수 없어요. 경험을 통해 얻어지는 것이에요.', example_en_5 = 'Her greeting was marked by an unmistakable gravitas.', example_ko_5 = '그녀의 인사에는 틀림없는 무게감이 담겨 있었어요.' WHERE id = 'w_greeting_C2_21';
UPDATE words SET example_en_2 = 'A sagacious host knows when to introduce guests and when to wait.', example_ko_2 = '현명한 호스트는 언제 손님을 소개하고 언제 기다려야 하는지 알아요.', example_en_3 = 'She was sagacious enough to keep her greeting brief and warm.', example_ko_3 = '그녀는 인사를 짧고 따뜻하게 유지할 만큼 현명했어요.', example_en_4 = 'His sagacious reading of the room made every introduction land well.', example_ko_4 = '그의 현명한 상황 파악 덕분에 모든 소개가 잘 전달됐어요.', example_en_5 = 'A sagacious person knows the weight of a well-timed greeting.', example_ko_5 = '현명한 사람은 적절한 시기의 인사의 무게를 알아요.' WHERE id = 'w_greeting_C2_22';
UPDATE words SET example_en_2 = 'She opened the speech with a felicitous reference to the occasion.', example_ko_2 = '그녀는 그 자리에 대한 적절한 언급으로 연설을 시작했어요.', example_en_3 = 'His felicitous choice of words made the introduction unforgettable.', example_ko_3 = '그의 적절한 말 선택이 소개를 잊을 수 없게 만들었어요.', example_en_4 = 'A felicitous greeting strikes the perfect balance of warmth and respect.', example_ko_4 = '적절한 인사는 따뜻함과 존중의 완벽한 균형을 맞춰요.', example_en_5 = 'She was known for finding the most felicitous way to greet anyone.', example_ko_5 = '그녀는 누구에게나 가장 적절하게 인사하는 방법을 찾는 것으로 알려져 있었어요.' WHERE id = 'w_greeting_C2_23';
UPDATE words SET example_en_2 = 'He received a bespoke welcome pack tailored to his interests.', example_ko_2 = '그는 자신의 관심사에 맞춤화된 개인화된 환영 팩을 받았어요.', example_en_3 = 'She prepared a bespoke introduction for each keynote speaker.', example_ko_3 = '그녀는 각 기조 연설자를 위해 개인화된 소개를 준비했어요.', example_en_4 = 'A bespoke greeting shows attention to detail and genuine care.', example_ko_4 = '개인화된 인사는 세심한 주의와 진심 어린 관심을 보여줘요.', example_en_5 = 'Bespoke welcomes make guests feel uniquely valued.', example_ko_5 = '개인화된 환영은 손님들이 특별히 소중하게 느끼게 해요.' WHERE id = 'w_greeting_C2_24';
UPDATE words SET example_en_2 = 'The soldier saluted as the general walked past.', example_ko_2 = '장군이 지나칠 때 병사는 경례했어요.', example_en_3 = 'She saluted the audience at the end of her performance.', example_ko_3 = '그녀는 공연이 끝나고 청중에게 경례했어요.', example_en_4 = 'He saluted his mentor whenever they crossed paths.', example_ko_4 = '그는 스승과 마주칠 때마다 경례했어요.', example_en_5 = 'To salute someone is to honor them with your greeting.', example_ko_5 = '누군가에게 경례하는 것은 인사로 그들을 공경하는 것이에요.' WHERE id = 'w_greeting_C2_25';
UPDATE words SET example_en_2 = 'The ceremony ended with a benediction from the elder.', example_ko_2 = '행사는 어른의 축복으로 마무리됐어요.', example_en_3 = 'She offered a gentle benediction to the departing guests.', example_ko_3 = '그녀는 떠나는 손님들에게 부드러운 축복을 건넸어요.', example_en_4 = 'He received a benediction before beginning his new role.', example_ko_4 = '그는 새로운 역할을 시작하기 전에 축복을 받았어요.', example_en_5 = 'A benediction closes a ceremony with warmth and grace.', example_ko_5 = '축복은 따뜻함과 은혜로 행사를 마무리해요.' WHERE id = 'w_greeting_C2_26';
UPDATE words SET example_en_2 = 'She specializes in teaching intercultural greeting etiquette.', example_ko_2 = '그녀는 이문화 간 인사 예절 가르치기를 전문으로 해요.', example_en_3 = 'Understanding intercultural norms prevents greeting faux pas.', example_ko_3 = '이문화 간 규범을 이해하면 인사 실수를 방지해요.', example_en_4 = 'Intercultural competence begins with learning how to say hello properly.', example_ko_4 = '이문화 간 능력은 제대로 인사하는 법을 배우는 것에서 시작돼요.', example_en_5 = 'She led an intercultural workshop on greeting customs worldwide.', example_ko_5 = '그녀는 전 세계 인사 관습에 관한 이문화 간 워크샵을 이끌었어요.' WHERE id = 'w_greeting_C2_27';
UPDATE words SET example_en_2 = 'He chose his parting words with great care and thought.', example_ko_2 = '그는 작별 인사를 매우 신중하게 골랐어요.', example_en_3 = 'Her parting smile lingered in his mind for days.', example_ko_3 = '그녀의 작별 미소가 며칠 동안 그의 마음에 남아 있었어요.', example_en_4 = 'A thoughtful parting is as important as a warm greeting.', example_ko_4 = '사려 깊은 작별은 따뜻한 인사만큼 중요해요.', example_en_5 = 'The parting of old friends was marked by warm hugs and promises.', example_ko_5 = '오래된 친구들의 작별은 따뜻한 포옹과 약속으로 표시됐어요.' WHERE id = 'w_greeting_C2_28';
UPDATE words SET example_en_2 = 'Her bow was the quintessential expression of Korean respect.', example_ko_2 = '그녀의 절은 한국식 존중의 전형적인 표현이었어요.', example_en_3 = 'He gave what could only be described as the quintessential handshake.', example_ko_3 = '그는 정말 전형적인 악수를 했어요.', example_en_4 = 'This is the quintessential way to greet in formal Korean settings.', example_ko_4 = '이것이 한국의 격식 있는 자리에서 인사하는 전형적인 방법이에요.', example_en_5 = 'She embodied the quintessential host, welcoming everyone with grace.', example_ko_5 = '그녀는 모든 사람을 은혜롭게 맞이하는 전형적인 호스트의 모습이었어요.' WHERE id = 'w_greeting_C2_29';
UPDATE words SET example_en_2 = 'He gravely acknowledged the loss before beginning his speech.', example_ko_2 = '그는 연설을 시작하기 전에 엄숙하게 그 손실을 인정했어요.', example_en_3 = 'She nodded gravely to the assembled guests.', example_ko_3 = '그녀는 모인 손님들에게 엄숙하게 고개를 끄덕였어요.', example_en_4 = 'He gravely thanked each person for their presence.', example_ko_4 = '그는 각자의 참석에 대해 엄숙하게 감사를 표했어요.', example_en_5 = 'Gravely acknowledging someone shows the depth of your respect.', example_ko_5 = '엄숙하게 누군가를 알아봐 주는 것은 존중의 깊이를 보여줘요.' WHERE id = 'w_greeting_C2_30';
UPDATE words SET example_en_2 = 'He was careful not to appear obsequious when greeting his boss.', example_ko_2 = '그는 상사에게 인사할 때 굽신거리게 보이지 않으려 조심했어요.', example_en_3 = 'She disliked obsequious behavior in professional settings.', example_ko_3 = '그녀는 전문적인 자리에서 굽신거리는 행동을 싫어했어요.', example_en_4 = 'There is a fine line between respectful and obsequious.', example_ko_4 = '존중스러운 것과 굽신거리는 것 사이에는 얇은 경계가 있어요.', example_en_5 = 'Avoid obsequious greetings — they rarely come across as genuine.', example_ko_5 = '굽신거리는 인사는 피하세요. 거의 진심으로 보이지 않아요.' WHERE id = 'w_greeting_C2_31';
UPDATE words SET example_en_2 = 'She remained sanguine even when the event did not go as planned.', example_ko_2 = '행사가 계획대로 되지 않았을 때도 그녀는 낙관적인 태도를 유지했어요.', example_en_3 = 'His sanguine outlook made meetings feel positive from the start.', example_ko_3 = '그의 낙관적인 시각 덕분에 회의가 처음부터 긍정적으로 느껴졌어요.', example_en_4 = 'A sanguine host makes guests feel optimistic and welcome.', example_ko_4 = '낙관적인 호스트는 손님들이 낙관적이고 환영받는 느낌을 받게 해요.', example_en_5 = 'She greeted each new challenge with a sanguine smile.', example_ko_5 = '그녀는 새로운 도전마다 낙관적인 미소로 맞이했어요.' WHERE id = 'w_greeting_C2_32';
UPDATE words SET example_en_2 = 'She waited for a propitious moment before making the introduction.', example_ko_2 = '그녀는 소개를 하기 전에 상서로운 순간을 기다렸어요.', example_en_3 = 'He saw the event as a propitious occasion for networking.', example_ko_3 = '그는 그 행사를 네트워킹을 위한 상서로운 기회로 봤어요.', example_en_4 = 'The propitious timing of the greeting opened a new partnership.', example_ko_4 = '상서로운 인사 타이밍이 새로운 파트너십을 열었어요.', example_en_5 = 'A propitious first meeting can set the course of a career.', example_ko_5 = '상서로운 첫 만남은 커리어의 방향을 결정할 수 있어요.' WHERE id = 'w_greeting_C2_33';
UPDATE words SET example_en_2 = 'She showed remarkable discernment in knowing when to approach.', example_ko_2 = '그녀는 언제 다가가야 하는지 아는 데 뛰어난 통찰력을 보였어요.', example_en_3 = 'His social discernment told him when formality was required.', example_ko_3 = '그의 사회적 통찰력은 격식이 필요한 때를 알려줬어요.', example_en_4 = 'Discernment in greetings means reading the room accurately.', example_ko_4 = '인사에서의 통찰력은 상황을 정확하게 읽는 것을 의미해요.', example_en_5 = 'She was respected for her sharp social discernment.', example_ko_5 = '그녀는 날카로운 사회적 통찰력으로 존경을 받았어요.' WHERE id = 'w_greeting_C2_34';
UPDATE words SET example_en_2 = 'There was something ineffable in the warmth of her welcome.', example_ko_2 = '그녀의 환영에는 말로 표현할 수 없는 따뜻함이 있었어요.', example_en_3 = 'He felt an ineffable sense of belonging when greeted by the community.', example_ko_3 = '공동체에서 환영을 받았을 때 그는 말로 표현할 수 없는 소속감을 느꼈어요.', example_en_4 = 'The ineffable quality of her greeting made it impossible to forget.', example_ko_4 = '그녀 인사의 말로 표현할 수 없는 특성이 그것을 잊을 수 없게 만들었어요.', example_en_5 = 'Some great introductions have an ineffable magic to them.', example_ko_5 = '어떤 훌륭한 소개에는 말로 표현할 수 없는 마법 같은 것이 있어요.' WHERE id = 'w_greeting_C2_35';
